-- ----------------------------
-- Table structure for evaluate
-- ----------------------------
DROP TABLE IF EXISTS `evaluate`;
CREATE TABLE `evaluate`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '评价ID',
  `user_id` int NOT NULL COMMENT '评价用户ID',
  `order_id` int NOT NULL COMMENT '关联的订单ID',
  `score` tinyint(1) NOT NULL DEFAULT 0 COMMENT '商品评分（1-5星）',
  `content` varchar(500) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT NULL COMMENT '评价文字内容',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '评价提交时间',
  `goods_id` int NULL DEFAULT NULL COMMENT '关联商品ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_order_id`(`order_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 601 CHARACTER SET = utf8mb3 COLLATE = utf8mb3_general_ci ROW_FORMAT = Dynamic;

