INSERT INTO `goods` VALUES (1, '童趣零食礼盒', '/picture/68-1.jpg', '/picture/68-2.jpg', '/picture/68-3.jpg', 128.9, '童趣零食礼盒外包装为卡通萌趣设计，印有经典动画形象，视觉上吸引儿童，礼盒内包含动物饼干、星星软糖、鳕鱼肠、溶豆、磨牙棒等12款儿童零食，独立小包装。开启时发出礼盒丝带的轻响，听觉上活泼，嗅觉上混合着奶香、果香等清新香气，无刺鼻味。触感零食或酥松或软糯，专为儿童设计口感，入口根据品类不同，或清甜或咸香，味觉上甜度均≤三星（满五星），无添加人工色素与香精。所有零食均符合儿童食品标准，保质期6-18个月不等，是节日礼盒中适合馈赠有娃家庭的童趣款。', 10, 8);
INSERT INTO `goods` VALUES (2, '草莓味磨牙棒', '/picture/35-1.jpg', '/picture/35-2.jpg', '/picture/35-3.jpg', 18.9, '草莓味磨牙棒呈长条状，视觉上淡粉色（天然草莓粉调色），表面有细密的纹理，适合儿童抓握磨牙。咬嚼时发出轻微的“咯吱”声，听觉上温和，嗅觉上淡淡的草莓果香混合着小麦的清香，清新不腻。触感坚硬但不硌牙，专为出牙期宝宝设计，能缓解牙龈不适，入口先是草莓的清甜，随即小麦的醇香散开，味觉上甜度极低（一星，满五星），无添加香精色素。主要原料：小麦粉、草莓粉、奶粉、橄榄油，保质期12个月，独立包装，干净卫生，是儿童零食中针对性的磨牙款。', 10, 3);
INSERT INTO `goods` VALUES (3, '咖啡伴侣礼盒', '/picture/71-1.jpg', '/picture/71-2.jpg', '/picture/71-3.jpg', 178.9, '咖啡伴侣礼盒外包装为简约轻奢设计，视觉上高级感十足，礼盒内包含各类口味曲奇、焦糖饼干、坚果仁、巧克力等8款搭配咖啡的零食，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着咖啡香（附赠挂耳咖啡）、奶香、焦糖香等，浓郁不腻。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上甜度覆盖二星至四星（满五星），与咖啡搭配口感互补。所有零食均采用低温工艺制作，保质期9-12个月不等，是节日礼盒中适合咖啡爱好者的轻奢款。', 10, 8);
INSERT INTO `goods` VALUES (4, '香蕉味泡芙球', '/picture/36-1.jpg', '/picture/36-2.jpg', '/picture/36-3.jpg', 22.9, '香蕉味泡芙球呈淡黄色的中空球状，视觉上小巧可爱，表面有细密的气孔，适合儿童抓食。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的香蕉果香混合着奶香，清新自然。触感空心酥脆，入口即化，先是香蕉的清甜在舌尖散开，随即奶香回味，味觉上甜度适中（二星，满五星），无添加人工香精。主要原料：香蕉泥、奶粉、小麦粉、植物油，保质期8个月，非油炸工艺，是儿童零食中口感轻盈的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (5, '精选羊肚菌脆片', '/picture/85-1.jpg', '/picture/85-2.jpg', '/picture/85-3.jpg', 218.9, '精选羊肚菌脆片采用云南特级羊肚菌制作，呈深褐色，视觉上菌纹清晰，完整无碎。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上羊肚菌的独特清香混合着淡淡的海盐香，清新自然。触感酥脆易嚼，入口先是羊肚菌的清鲜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工调味，冻干工艺保留羊肚菌营养。主要原料：云南特级羊肚菌、食用海盐，冻干工艺，保质期10个月，独立包装，是高端零食中兼具营养与口感的特色款。', 10, 11);
INSERT INTO `goods` VALUES (6, '蓝莓味果泥', '/picture/37-1.jpg', '/picture/37-2.jpg', '/picture/37-3.jpg', 21.9, '蓝莓味果泥呈深紫色的泥状，视觉上质地细腻无颗粒，包装为便携吸嘴袋，方便儿童食用。挤压时触感顺滑，听觉上无明显声响，嗅觉上浓郁的蓝莓果香，清新不刺鼻，无香精味。入口绵密顺滑，无需咀嚼，先是蓝莓的酸甜在舌尖散开，随即水果的自然清甜回味，味觉上无添加蔗糖（一星，满五星），仅靠蓝莓自然提甜。主要原料：蓝莓果肉（≥90%）、苹果泥、维生素C，保质期12个月，无防腐剂，是儿童零食中补充花青素的营养款。', 10, 3);
INSERT INTO `goods` VALUES (7, '五香开口松子', '/picture/46-1.jpg', '/picture/46-2.jpg', '/picture/46-3.jpg', 69.9, '五香开口松子外壳呈棕红色，开口均匀，视觉上颗粒饱满修长，果仁呈淡黄色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上浓郁的五香料香混合着松子的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是五香的咸香，随即松子的清甜散开，味觉上咸淡适中（二星，满五星），五香味浓郁且不掩盖松子本身的香气，越嚼越有回甘。主要原料：松子、五香粉、食用盐，低温烘焙，保质期8个月，无添加香精，是坚果系列中咸香风味的特色款。', 10, 4);
INSERT INTO `goods` VALUES (8, '孜然味烤鱿鱼板', '/picture/61-1.jpg', '/picture/61-2.jpg', '/picture/61-3.jpg', 47.9, '孜然味烤鱿鱼板呈深棕色，表面有孜然颗粒的均匀分布，视觉上板状完整，厚度均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上孜然的辛香混合着鱿鱼的鲜香，独特诱人。触感柔韧有嚼劲，入口先是鱿鱼的鲜甜，随即孜然的咸香在舌尖散开，味觉上咸淡适中（二星，满五星），孜然味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼板、孜然粉、食用盐、白砂糖，碳烤工艺，保质期9个月，是海鲜零食中孜然风味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (9, '芝士咸味饼干', '/picture/1768183025317.jpg', '/picture/1768183025334.jpg', '/picture/1768183025348.jpg', 19.9, '芝士咸味饼干呈淡黄色，表面有芝士粉的均匀附着，视觉上质感十足。轻咬时发出清脆的脆响，嗅觉上浓郁的芝士咸香混合着黄油香气，诱人食欲。触感酥脆不粘牙，入口先是芝士的咸香醇厚，随即黄油的绵密感在舌尖散开，味觉上咸度适中，还带着芝士特有的微酸回甘，层次丰富。主要原料：芝士粉、黄油、小麦粉、食用盐，甜度：一星（满五星），保质期10个月，芝士含量≥15%，是饼干系列中咸味芝士控的必选款。', 10, 1);
INSERT INTO `goods` VALUES (10, '番茄味薯片脆', '/picture/1768183053016.jpg', '/picture/1768183053030.jpg', '/picture/1768183053075.jpg', 7.9, '番茄味薯片脆呈薄透的橙红色，表面裹满番茄粉，视觉上色彩鲜亮。咬下时发出清脆的“啪”声，听觉上解压十足，嗅觉上浓郁的番茄酸甜果香混合着土豆香，清新不腻。触感薄脆易嚼，入口即化，先是番茄的酸甜在舌尖迸发，随即土豆的醇香回味，味觉上酸甜平衡，番茄味浓郁且不齁甜。主要原料：马铃薯片、番茄粉、白砂糖、食用盐，保质期10个月，薄切烘烤工艺，低脂低油，是膨化系列中经典的番茄风味款。', 11, 2);
INSERT INTO `goods` VALUES (11, '原味鲜虾片', '/picture/1768183083877.jpg', '/picture/1768183083891.jpg', '/picture/11-3.jpg', 23.9, '原味鲜虾片呈薄透的淡粉色，视觉上轻盈通透，能看到细微的虾粉颗粒。咬下时发出清脆的“啪”声，听觉上解压有趣，嗅觉上浓郁的鲜虾鲜香，清新无腥味。触感薄脆易嚼，入口即化，先是鲜虾的鲜甜在舌尖散开，随即淡淡的盐味提味，味觉上咸淡适中（一星，满五星），无添加人工香精。主要原料：虾粉（≥40%）、小麦粉、食用盐、植物油，保质期9个月，非油炸烘烤，是儿童零食中补充优质蛋白的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (12, '柠檬味烤鱼片', '/picture/1768183098288.jpg', '/picture/12-2.jpg', '/picture/12-3.jpg', 44.9, '柠檬味烤鱼片呈淡黄色，视觉上质地轻薄，纹理清晰。咬下时发出轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上柠檬的清香混合着鱼肉的鲜香，清新不腻。触感柔韧有嚼劲，入口先是柠檬的酸甜，随即鱼肉的鲜甜散开，味觉上酸甜平衡（二星，满五星），柠檬味掩盖了鱼肉的腥味，口感更清新。主要原料：马面鱼、柠檬汁、食用盐、白砂糖，低温烘烤，保质期10个月，是海鲜零食中清新风味的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (13, '抹茶红豆夹心饼干', '/picture/1768183115678.jpg', '/picture/13-2.jpg', '/picture/13-3.jpg', 16.9, '抹茶红豆夹心饼干外层是淡绿色的抹茶饼干体，中间夹着暗红色的红豆沙夹心，视觉上配色清新雅致。掰开时能听到饼干体轻微的脆响，夹心则软糯拉丝，嗅觉上宇治抹茶的清苦香气混合着红豆的甜香，淡雅宜人。触感外层酥脆，夹心绵密，入口先是抹茶的清苦，随即红豆夹心的香甜中和苦味，味觉上甜苦平衡，还带着抹茶特有的茶韵回甘。主要原料：宇治抹茶粉、红豆沙、小麦粉、黄油，甜度：三星（满五星），保质期9个月，无人工色素，是饼干系列中兼具日式风味的特色款。', 10, 1);
INSERT INTO `goods` VALUES (14, '海盐焦糖饼干', '/picture/1768183141942.jpg', '/picture/14-2.jpg', '/picture/14-3.jpg', 14.9, '海盐焦糖饼干呈焦糖色，表面有细密的盐粒点缀，视觉上光泽诱人。轻咬时发出清脆的“咔嚓”声，嗅觉上浓郁的焦糖香气混合着淡淡的海盐气息，甜咸交织。触感酥脆易断，入口先是焦糖的焦香甜味，随即海盐的咸香在舌尖散开，中和甜腻，味觉上回味有淡淡的黄油香，层次丰富。主要原料：焦糖酱、食用海盐、小麦粉、黄油，甜度：四星（满五星），保质期10个月，采用低温烘烤工艺，是饼干系列中甜咸风味的热门款。', 10, 1);
INSERT INTO `goods` VALUES (15, '花生酱夹心饼干', '/picture/15-1.jpg', '/picture/15-2.jpg', '/picture/15-3.jpg', 13.9, '花生酱夹心饼干外层是金黄色的酥性饼干，中间夹着醇厚的花生酱夹心，视觉上饱满厚实。掰开时能听到饼干的脆响，同时花生酱夹心会微微拉丝，嗅觉上浓郁的花生烘烤香气扑面而来，醇厚不腻。触感外层酥脆，夹心绵密，入口先是饼干的酥松，随即花生酱的咸香与微甜在口腔中散开，味觉上花生味浓郁，还带着一丝烘烤的焦香。主要原料：花生酱、小麦粉、黄油、白砂糖，甜度：三星（满五星），保质期9个月，花生酱含量≥30%，是饼干系列中经典的咸甜夹心款。', 10, 1);
INSERT INTO `goods` VALUES (16, '椰香薄脆饼干', '/picture/16-1.jpg', '/picture/16-2.jpg', '/picture/16-3.jpg', 11.9, '椰香薄脆饼干呈薄透的奶白色，能看到细密的椰蓉颗粒，视觉上轻盈通透。咬下时发出清脆的“咔嚓”声，嗅觉上浓郁的椰香混合着小麦的清香，清新自然。触感薄脆易嚼，入口即化，先是椰蓉的香甜在舌尖散开，随即小麦的醇香回味，味觉上甜而不腻，椰香浓郁且持久。主要原料：椰蓉、小麦粉、黄油、椰奶，甜度：二星（满五星），保质期11个月，采用薄切烘烤工艺，是饼干系列中口感轻盈的休闲款。', 10, 1);
INSERT INTO `goods` VALUES (17, '紫薯燕麦饼干', '/picture/17-1.jpg', '/picture/17-2.jpg', '/picture/17-3.jpg', 17.9, '紫薯燕麦饼干呈淡紫色，嵌有燕麦片的颗粒，视觉上健康自然。掰开时能听到燕麦片与饼干体碰撞的轻微声响，嗅觉上紫薯的香甜混合着燕麦的谷物香气，清淡不腻。触感酥松中带着燕麦的嚼劲，入口先是紫薯的清甜，随即燕麦的谷物香在口腔中散开，味觉上低糖低脂，口感丰富，还带着一丝谷物的回甘。主要原料：紫薯泥、燕麦片、小麦粉、橄榄油，甜度：一星（满五星），保质期8个月，无添加蔗糖，是饼干系列中健康代餐的优选款。', 10, 1);
INSERT INTO `goods` VALUES (19, '红豆薏米饼干', '/picture/19-1.jpg', '/picture/19-2.jpg', '/picture/19-3.jpg', 15.9, '红豆薏米饼干呈浅棕色，能看到红豆与薏米的颗粒，视觉上健康质朴。掰开时发出轻微的酥响，嗅觉上红豆的香甜混合着薏米的谷物清香，淡雅宜人。触感酥松易嚼，入口先是谷物的醇香，随即红豆的清甜散开，味觉上低糖清淡，还带着薏米的微甘，饱腹感强。主要原料：红豆粉、薏米粉、小麦粉、植物油，甜度：一星（满五星），保质期9个月，无添加防腐剂，是饼干系列中主打健康养生的特色款。', 10, 1);
INSERT INTO `goods` VALUES (20, '原味空心薯笛', '/picture/20-1.jpg', '/picture/20-2.jpg', '/picture/20-3.jpg', 8.9, '原味空心薯笛呈金黄的中空管状，表面有细密的纹理，视觉上酥脆诱人。咬下时发出“咔嚓”的清脆声响，听觉上极具解压感，嗅觉上浓郁的土豆原香扑面而来，清新自然。触感空心酥脆，轻捏即碎，入口先是土豆的醇香，随即淡淡的盐味提味，味觉上咸淡适中，薯香浓郁且不油腻，越嚼越有谷物的回甘。主要原料：马铃薯粉、玉米淀粉、食用盐、棕榈油，保质期9个月，采用非油炸膨化工艺，低脂轻卡，是膨化系列中经典的原味休闲款，适合全家共享。', 10, 2);
INSERT INTO `goods` VALUES (21, '烧烤味玉米浪', '/picture/21-1.jpg', '/picture/21-2.jpg', '/picture/21-3.jpg', 9.9, '烧烤味玉米浪呈波浪形的金黄色，表面均匀附着烧烤调味料，视觉上色泽诱人。咬开时发出“咔嚓”的脆响，听觉上清脆悦耳，嗅觉上浓郁的烧烤香料香混合着玉米的清甜，层次丰富。触感波浪形的酥脆质感，入口先是玉米的香甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡，还带着一丝烟熏的香气，回味悠长。主要原料：玉米粉、烧烤调味料、植物油、白砂糖，保质期8个月，非油炸工艺，是膨化系列中风味浓郁的热门款。', 10, 2);
INSERT INTO `goods` VALUES (22, '黑巧克力榛子饼干', '/picture/22-1.jpg', '/picture/22-2.jpg', '/picture/22-3.jpg', 15.9, '黑巧克力榛子饼干通体呈深棕色调，嵌有饱满的榛子碎，视觉上极具质感。轻咬时能听到巧克力脆皮与饼干酥层碰撞的脆响，嗅觉上立刻捕捉到微苦的黑巧克力香与烘烤榛子的坚果香气，层次丰富。触感酥脆中带着榛子的微硬颗粒感，入口先是黑巧克力的微苦醇厚，随即榛子的香脆与饼干的酥松融合，甜苦平衡，味觉上回味悠长。主要原料：可可含量70%的黑巧克力、榛子仁、低筋面粉、黄油，甜度：二星（满五星），保质期10个月，不含反式脂肪酸，是饼干系列中兼具巧克力风味与坚果口感的特色款。', 10, 1);
INSERT INTO `goods` VALUES (23, '海苔味米饼', '/picture/23-1.jpg', '/picture/23-2.jpg', '/picture/23-3.jpg', 10.9, '海苔味米饼呈米白色，表面有海苔碎的均匀分布，视觉上清新素雅。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上海苔的鲜咸香气混合着大米的清香，淡雅宜人。触感酥脆中带着大米的蓬松感，入口先是大米的醇香，随即海苔的鲜咸散开，味觉上咸淡适中，还带着一丝米香的回甘，口感轻盈不腻。主要原料：大米粉、海苔碎、食用盐、植物油，保质期12个月，非油炸膨化，是膨化系列中适合儿童的清淡款。', 10, 2);
INSERT INTO `goods` VALUES (24, '香辣味虾条', '/picture/24-1.jpg', '/picture/24-2.jpg', '/picture/24-3.jpg', 11.9, '香辣味虾条呈橙红色的长条状，表面裹满香辣调味料，视觉上色泽诱人。咬下时发出“咔嚓”的脆响，听觉上极具满足感，嗅觉上浓郁的虾香混合着辣椒的辛香，香气扑鼻。触感酥脆不粘牙，入口先是鲜虾的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中，咸香入味，虾味浓郁且持久。主要原料：虾粉、小麦粉、辣椒面、植物油，保质期8个月，虾粉含量≥15%，是膨化系列中重口味爱好者的优选款。', 10, 2);
INSERT INTO `goods` VALUES (25, '芝士味空心脆', '/picture/25-1.jpg', '/picture/25-2.jpg', '/picture/25-3.jpg', 13.9, '芝士味空心脆呈淡黄色的中空球状，表面有芝士粉的附着，视觉上呆萌可爱。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的芝士咸香混合着奶香，醇厚诱人。触感空心酥脆，入口即碎，先是芝士的咸香在口腔中散开，随即奶香回味，味觉上咸甜平衡，芝士味浓郁且不腻。主要原料：芝士粉、小麦粉、黄油、食用盐，保质期9个月，非油炸工艺，是膨化系列中芝士控的必选款。', 10, 2);
INSERT INTO `goods` VALUES (26, '芥末味青豆脆', '/picture/26-1.jpg', '/picture/26-2.jpg', '/picture/26-3.jpg', 12.9, '芥末味青豆脆呈翠绿色，包裹着淡淡的芥末调味粉，视觉上清新亮眼。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上芥末的微辛香气混合着青豆的清香，层次独特。触感酥脆中带着青豆的颗粒感，入口先是青豆的清甜，随即芥末的微辛在舌尖散开，味觉上辛而不辣，咸香入味，越嚼越有青豆的回甘。主要原料：青豆、芥末粉、食用盐、植物油，保质期10个月，低温膨化工艺，是膨化系列中风味独特的小众款。', 10, 2);
INSERT INTO `goods` VALUES (27, '蜂蜜黄油味薯条', '/picture/27-1.jpg', '/picture/27-2.jpg', '/picture/27-3.jpg', 14.9, '蜂蜜黄油味薯条呈金黄的长条状，表面裹满蜂蜜黄油酱，视觉上光泽诱人。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的黄油香混合着蜂蜜的甜香，甜而不腻。触感酥脆中带着微微的绵密感，入口先是黄油的醇厚，随即蜂蜜的清甜散开，味觉上甜咸平衡，黄油味浓郁且回味有奶香。主要原料：马铃薯条、黄油、蜂蜜、食用盐，保质期8个月，非油炸烘烤，是膨化系列中甜咸风味的热门款。', 10, 2);
INSERT INTO `goods` VALUES (28, '藤椒味洋芋片', '/picture/28-1.jpg', '/picture/28-2.jpg', '/picture/28-3.jpg', 10.9, '藤椒味洋芋片呈薄透的淡黄色，表面有藤椒粉的均匀附着，视觉上清爽质朴。咬下时发出“啪”的清脆声响，听觉上解压有趣，嗅觉上藤椒的麻香混合着土豆的清香，独特诱人。触感薄脆易嚼，入口先是土豆的醇香，随即藤椒的麻香在舌尖散开，味觉上麻而不苦，咸香入味，还带着一丝藤椒的清鲜。主要原料：马铃薯片、藤椒粉、食用盐、植物油，保质期9个月，薄切工艺，是膨化系列中川味特色的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (29, '肉松味米卷', '/picture/29-1.jpg', '/picture/29-2.jpg', '/picture/29-3.jpg', 15.9, '肉松味米卷呈米白色的卷状，表面裹满肉松碎，视觉上饱满诱人。咬开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上肉松的咸香混合着大米的清香，浓郁不腻。触感外层酥脆，内芯蓬松，入口先是肉松的咸香，随即大米的醇香散开，味觉上咸甜适中，肉松味浓郁且有嚼劲。主要原料：大米粉、肉松、白砂糖、食用盐，保质期12个月，非油炸膨化，是膨化系列中饱腹感强的代餐款。', 10, 2);
INSERT INTO `goods` VALUES (30, '海盐味豌豆脆', '/picture/30-1.jpg', '/picture/30-2.jpg', '/picture/30-3.jpg', 11.9, '海盐味豌豆脆呈淡绿色，表面有细密的海盐颗粒，视觉上清新自然。咬下时发出“咔嚓”的脆响，听觉上解压十足，嗅觉上豌豆的清香混合着海盐的咸香，清淡不腻。触感酥脆易嚼，入口先是豌豆的清甜，随即海盐的咸香提味，味觉上咸淡适中，豌豆味浓郁且回甘持久。主要原料：豌豆粉、食用海盐、植物油、玉米淀粉，保质期10个月，非油炸工艺，是膨化系列中健康轻卡的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (31, '香葱咸味苏打饼干', '/picture/31-1.jpg', '/picture/31-2.jpg', '/picture/31-3.jpg', 9.8, '香葱咸味苏打饼干呈奶白色基底，点缀着翠绿的香葱碎，视觉上清新自然。掰开时发出“啪”的清脆声响，嗅觉上浓郁的香葱香气混合着小麦的清香扑面而来，咸香不刺鼻。触感干爽不粘手，酥松易嚼，入口先是淡淡的小麦香，紧接着香葱的鲜咸在舌尖散开，口感清爽不腻，味觉上咸度适中，还带着苏打饼干特有的微碱性回甘。主要原料：小麦粉、香葱、食用纯碱、食用盐，甜度：一星（满五星），保质期9个月，无额外添加蔗糖，适合控糖人群，是饼干系列中经典的咸味休闲款。', 10, 1);
INSERT INTO `goods` VALUES (32, '水果味星星软糖', '/picture/32-1.jpg', '/picture/32-2.jpg', '/picture/32-3.jpg', 19.9, '水果味星星软糖呈五彩的星星造型，视觉上色彩鲜艳（采用天然果蔬色素），颗颗饱满晶莹，萌趣十足。捏动时触感Q弹软糯，无硬芯，听觉上无明显声响，嗅觉上浓郁的草莓、橙子、葡萄等混合水果果香，清新不刺鼻。入口软糯有嚼劲，不粘牙，先是草莓的酸甜在舌尖散开，随即橙子的清香、葡萄的清甜依次迸发，味觉上甜度适中（二星，满五星），无添加人工香精与防腐剂。主要原料：麦芽糖浆、天然果蔬汁、明胶、维生素C，保质期18个月，每颗独立包装，干净卫生，是儿童零食中补充维生素的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (33, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (34, '原味溶豆（酸奶味）', '/picture/34-1.jpg', '/picture/34-2.jpg', '/picture/34-3.jpg', 29.9, '酸奶味溶豆呈迷你的小颗粒状，视觉上奶白色，蓬松轻盈，造型小巧适合儿童抓握。轻捏即碎，触感绵软，听觉上无明显声响，嗅觉上浓郁的酸奶奶香，清新自然。入口即溶，无需咀嚼，先是酸奶的酸甜在舌尖化开，随即奶香回味，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠酸奶自然提味。主要原料：酸奶、奶粉、玉米淀粉、益生菌，保质期6个月，冻干工艺锁鲜，是儿童零食中适合低龄宝宝的辅食款。', 10, 3);
INSERT INTO `goods` VALUES (35, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (36, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (37, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (38, '芝士味小馒头', '/picture/38-1.jpg', '/picture/38-2.jpg', '/picture/38-3.jpg', 17.9, '芝士味小馒头呈迷你的奶黄色球状，视觉上小巧圆润，适合儿童抓握食用。咬下时发出轻微的“咔嚓”声，听觉上温和，嗅觉上浓郁的芝士香混合着奶香，醇厚不腻。触感酥松易嚼，入口即化，先是芝士的咸香在舌尖散开，随即奶香回味，味觉上咸甜适中（二星，满五星），无添加人工色素。主要原料：奶粉、芝士粉、小麦粉、鸡蛋，保质期10个月，独立小包装，是儿童零食中经典的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (39, '芒果味QQ糖', '/picture/39-1.jpg', '/picture/39-2.jpg', '/picture/39-3.jpg', 15.9, '芒果味QQ糖呈芒果形状的半透明状，视觉上金黄诱人，造型逼真可爱。捏动时触感Q弹有弹性，听觉上无明显声响，嗅觉上浓郁的芒果果香，清新自然无异味。入口软糯有嚼劲，不粘牙，先是芒果的清甜在舌尖散开，随即淡淡的果酸提味，味觉上甜度适中（三星，满五星），采用天然芒果汁调色调味。主要原料：麦芽糖浆、芒果汁、明胶、柠檬酸，保质期18个月，独立包装，是儿童零食中趣味十足的糖果款。', 10, 3);
INSERT INTO `goods` VALUES (40, '鳕鱼肠（芝士味）', '/picture/40-1.jpg', '/picture/40-2.jpg', '/picture/40-3.jpg', 25.9, '芝士味鳕鱼肠呈奶白色的长条状，视觉上质地均匀，无杂质，包装上印有卡通图案，吸引儿童。咬开时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的鳕鱼鲜香混合着芝士的咸香，醇厚不腻。触感弹嫩有嚼劲，专为儿童设计的软嫩口感，入口先是鳕鱼的鲜甜，随即芝士的咸香在口腔中散开，味觉上咸淡适中，无腥味，芝士味浓郁且自然。主要原料：鳕鱼肉（≥60%）、芝士粉、鸡蛋、食用盐，保质期9个月，独立真空包装，开袋即食，是儿童零食中补充优质蛋白的营养款。', 10, 3);
INSERT INTO `goods` VALUES (41, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (42, '原味手剥巴旦木', '/picture/42-1.jpg', '/picture/42-2.jpg', '/picture/42-3.jpg', 39.9, '原味手剥巴旦木外壳呈浅棕色，带有自然的纹理，视觉上饱满厚实，果仁呈奶白色，颗粒均匀。剥开外壳时能听到轻微的“咔嚓”声，听觉上解压，嗅觉上浓郁的巴旦木坚果原香，清淡不腻。触外壳坚硬但易剥，果仁触感饱满酥脆，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无额外调味（一星，满五星），仅靠巴旦木自然的咸香，越嚼越香，回甘持久。主要原料：精选巴旦木，无添加任何调味料，保质期12个月，低温烘焙锁鲜，是坚果系列中保留原味的经典款，富含优质脂肪与维生素E。', 10, 4);
INSERT INTO `goods` VALUES (43, '盐焗夏威夷果', '/picture/43-1.jpg', '/picture/43-2.jpg', '/picture/43-3.jpg', 59.9, '盐焗夏威夷果外壳呈棕褐色，带有天然的纹理，配有开果器，视觉上颗粒饱满圆润。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的坚果香混合着淡淡的海盐气息，咸香诱人。触感果仁绵密酥脆，入口先是海盐的咸香提味，随即夏威夷果特有的奶香在口腔中散开，味觉上咸甜平衡（二星，满五星），口感绵密且不腻，越嚼越有奶香回甘。主要原料：夏威夷果、食用海盐，低温烘焙，保质期10个月，无添加防腐剂，是坚果系列中口感绵密的高端款。', 10, 4);
INSERT INTO `goods` VALUES (44, '炭烧腰果', '/picture/44-1.jpg', '/picture/44-2.jpg', '/picture/44-3.jpg', 45.9, '炭烧腰果呈焦糖色，表面有细密的炭烧纹理，视觉上色泽诱人，颗粒饱满无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的炭烧香混合着腰果的坚果香，层次丰富。触感酥脆不粘牙，入口先是炭烧的焦香，随即腰果的清甜散开，味觉上咸甜适中（三星，满五星），炭烧味浓郁且不糊，回味有坚果的醇香。主要原料：腰果、白砂糖、食用盐、植物油，低温炭烧工艺，保质期11个月，是坚果系列中风味独特的热门款。', 10, 4);
INSERT INTO `goods` VALUES (45, '蜂蜜琥珀核桃仁', '/picture/45-1.jpg', '/picture/45-2.jpg', '/picture/45-3.jpg', 38.9, '蜂蜜琥珀核桃仁呈透亮的焦糖色，包裹着一层薄蜜，视觉上光泽诱人，核桃仁完整无碎。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的蜂蜜甜香混合着核桃的坚果香，甜而不腻。触感酥脆中带着微微的粘糯，入口先是蜂蜜的清甜，随即核桃的醇香在舌尖散开，味觉上甜咸平衡（四星，满五星），蜂蜜味浓郁且不齁甜，核桃的苦涩感被中和得恰到好处。主要原料：核桃仁、蜂蜜、白砂糖、白芝麻，低温熬煮挂浆，保质期9个月，是坚果系列中甜口的经典款。', 10, 4);
INSERT INTO `goods` VALUES (47, '原味碧根果', '/picture/47-1.jpg', '/picture/47-2.jpg', '/picture/47-3.jpg', 55.9, '原味碧根果外壳呈浅棕色，带有自然的裂纹，视觉上果仁饱满，易剥取。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的碧根果坚果香，清淡不腻，无额外调味。触感果仁酥脆绵密，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无添加（一星，满五星），仅靠碧根果自然的咸香，口感绵密且回味悠长。主要原料：精选碧根果，低温烘焙，保质期12个月，是坚果系列中保留原味的高端款，富含不饱和脂肪酸。', 10, 4);
INSERT INTO `goods` VALUES (48, '香辣花生', '/picture/48-1.jpg', '/picture/48-2.jpg', '/picture/48-3.jpg', 19.9, '香辣花生呈红棕色，表面裹满香辣调味料，视觉上色泽鲜亮，颗粒饱满无瘪粒。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的辣椒香混合着花生的烘烤香，香气扑鼻。触感酥脆不粘牙，入口先是花生的香甜，随即香辣味在舌尖散开，味觉上辣度适中（三星，满五星），咸香入味，花生的醇香与辣椒的辛香融合恰到好处。主要原料：花生、辣椒面、花椒粉、食用盐，低温烘烤，保质期10个月，是坚果系列中重口味的平价款。', 10, 4);
INSERT INTO `goods` VALUES (49, '抹茶味杏仁', '/picture/49-1.jpg', '/picture/49-2.jpg', '/picture/49-3.jpg', 42.9, '抹茶味杏仁呈淡绿色，表面均匀附着抹茶粉，视觉上清新雅致，杏仁颗粒完整。咬下时发出“咔嚓”的脆响，听觉上清脆，嗅觉上宇治抹茶的清苦香气混合着杏仁的坚果香，层次独特。触感酥脆易嚼，入口先是抹茶的清苦，随即杏仁的清甜散开，味觉上甜苦平衡（二星，满五星），抹茶味浓郁且不涩，杏仁的醇香回味持久。主要原料：杏仁、宇治抹茶粉、白砂糖、植物油，低温烘焙，保质期9个月，是坚果系列中风味新颖的特色款。', 10, 4);
INSERT INTO `goods` VALUES (50, '盐焗开心果', '/picture/50-1.jpg', '/picture/50-2.jpg', '/picture/50-3.jpg', 68.9, '盐焗开心果外壳呈淡绿色，开口率≥95%，视觉上颗粒饱满，果仁呈翠绿色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上淡淡的海盐香混合着开心果的坚果香，清新自然。触感果仁酥脆有嚼劲，入口先是海盐的咸香提味，随即开心果的清甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留开心果的自然风味。主要原料：开心果、食用海盐，低温烘焙，保质期11个月，是坚果系列中健康轻盐的高端款。', 10, 4);
INSERT INTO `goods` VALUES (51, '椰香腰果', '/picture/51-1.jpg', '/picture/51-2.jpg', '/picture/51-3.jpg', 48.9, '椰香腰果呈奶白色，表面裹满椰蓉，视觉上蓬松诱人，颗粒饱满。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上浓郁的椰香混合着腰果的坚果香，清新不腻。触感酥脆中带着椰蓉的绵软，入口先是椰蓉的香甜，随即腰果的醇香散开，味觉上甜而不腻（三星，满五星），椰香浓郁且持久，腰果的口感丰富有层次。主要原料：腰果、椰蓉、白砂糖、黄油，低温烘焙，保质期10个月，是坚果系列中甜口的特色款。', 10, 4);
INSERT INTO `goods` VALUES (52, '椒盐核桃', '/picture/52-1.jpg', '/picture/52-2.jpg', '/picture/52-3.jpg', 29.9, '椒盐核桃外壳呈深棕色，带有椒盐的均匀附着，视觉上纹理清晰，易剥开。撬开外壳时发出“啪”的轻响，听觉上解压，嗅觉上椒盐的咸香混合着核桃的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是椒盐的咸香，随即核桃的醇香散开，味觉上咸淡适中（二星，满五星），椒盐味掩盖了核桃的苦涩，口感更易接受。主要原料：核桃、椒盐粉、食用盐，低温烘焙，保质期12个月，是坚果系列中平价且风味佳的经典款。', 10, 4);
INSERT INTO `goods` VALUES (53, '原味碳烤鱿鱼丝', '/picture/53-1.jpg', '/picture/53-2.jpg', '/picture/53-3.jpg', 45.9, '原味碳烤鱿鱼丝呈深棕色，纹理清晰，视觉上丝丝分明，无碎渣。撕扯时能听到轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上浓郁的碳烤鱿鱼香，混合着淡淡的海鲜咸香，无腥味。触感柔韧有嚼劲，不粘牙，入口先是鱿鱼的鲜甜，随即碳烤的焦香在舌尖散开，味觉上咸淡适中（二星，满五星），无添加人工香精，仅靠鱿鱼本身的鲜味提味，越嚼越有海鲜的回甘。主要原料：新鲜鱿鱼、食用盐、白砂糖，碳烤工艺锁鲜，保质期9个月，独立真空包装，是海鲜零食中经典的手撕休闲款。', 10, 5);
INSERT INTO `goods` VALUES (54, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (55, '原味即食烤虾', '/picture/55-1.jpg', '/picture/55-2.jpg', '/picture/55-3.jpg', 68.9, '原味即食烤虾呈淡红色，视觉上虾身完整，个头均匀，肉质紧实。咬开时发出“咔嚓”的脆响（虾壳），听觉上满足，嗅觉上浓郁的鲜虾烘烤香，清新无腥味。触感虾壳酥脆，虾肉紧实有嚼劲，入口先是虾壳的咸香，随即虾肉的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留鲜虾的自然风味。主要原料：新鲜海虾、食用盐，低温碳烤，保质期10个月，独立包装，是海鲜零食中高蛋白的健康款。', 10, 5);
INSERT INTO `goods` VALUES (56, '烧烤味鱿鱼须', '/picture/56-1.jpg', '/picture/56-2.jpg', '/picture/56-3.jpg', 49.9, '烧烤味鱿鱼须呈深棕色，表面裹满烧烤调味料，视觉上须足完整，无断节。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的烧烤香料香混合着鱿鱼的鲜香，层次丰富。触感柔韧有嚼劲，不塞牙，入口先是鱿鱼的鲜甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡（三星，满五星），烧烤味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼须、烧烤调味料、食用盐、白砂糖，碳烤工艺，保质期8个月，是海鲜零食中风味浓郁的热门款。', 10, 5);
INSERT INTO `goods` VALUES (57, '泡椒味鱼皮', '/picture/57-1.jpg', '/picture/57-2.jpg', '/picture/57-3.jpg', 38.9, '泡椒味鱼皮呈淡黄色，点缀着泡椒的红色，视觉上色泽鲜亮，鱼皮完整。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上泡椒的酸辣香混合着鱼皮的鲜香，独特诱人。触感酥脆不粘牙，入口先是泡椒的酸辣，随即鱼皮的鲜香散开，味觉上酸辣适中（四星，满五星），鱼皮的酥脆与泡椒的酸爽融合，越嚼越香。主要原料：鱼皮、泡椒、食用盐、白醋，低温油炸（控油），保质期9个月，是海鲜零食中酸辣风味的小众款。', 10, 5);
INSERT INTO `goods` VALUES (58, '原味银鱼仔', '/picture/58-1.jpg', '/picture/58-2.jpg', '/picture/58-3.jpg', 42.9, '原味银鱼仔呈银白色，视觉上体型小巧均匀，无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的银鱼鲜香，混合着淡淡的海盐香，清新自然。触感柔韧有嚼劲，入口先是银鱼的鲜甜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工香精，保留银鱼的自然风味。主要原料：银鱼、食用盐、白砂糖，低温烘烤，保质期10个月，独立小包装，是海鲜零食中便携的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (59, '麻辣味花蛤肉', '/picture/59-1.jpg', '/picture/59-2.jpg', '/picture/59-3.jpg', 55.9, '麻辣味花蛤肉呈红棕色，表面裹满麻辣调味料，视觉上肉质饱满，无沙粒。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的麻辣香混合着花蛤的鲜香，香气扑鼻。触感肉质紧实有嚼劲，入口先是花蛤的鲜甜，随即麻辣味在舌尖散开，味觉上麻辣适中（五星，满五星），咸香入味，花蛤的鲜味与麻辣味融合恰到好处。主要原料：花蛤肉、辣椒面、花椒粉、食用盐，高温灭菌，保质期12个月，罐装密封，是海鲜零食中重口味的下酒菜。', 10, 5);
INSERT INTO `goods` VALUES (60, '芝士味鳕鱼粒', '/picture/60-1.jpg', '/picture/60-2.jpg', '/picture/60-3.jpg', 62.9, '芝士味鳕鱼粒呈奶白色，表面有芝士粉的均匀附着，视觉上颗粒饱满，质地细腻。咬下时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的芝士香混合着鳕鱼的鲜香，醇厚诱人。触感绵软有嚼劲，入口先是芝士的咸香，随即鳕鱼的鲜甜散开，味觉上咸甜平衡（二星，满五星），芝士味浓郁且不腻，鳕鱼的口感绵密。主要原料：鳕鱼肉、芝士粉、鸡蛋、食用盐，低温烘烤，保质期8个月，是海鲜零食中适合儿童的营养款。', 10, 5);
INSERT INTO `goods` VALUES (62, '盐焗味蛏子干', '/picture/62-1.jpg', '/picture/62-2.jpg', '/picture/62-3.jpg', 72.9, '盐焗味蛏子干呈淡黄色，视觉上肉质饱满，无沙无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上淡淡的海盐香混合着蛏子的鲜香，清新自然。触感肉质紧实有嚼劲，入口先是海盐的咸香，随即蛏子的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留蛏子的自然风味。主要原料：蛏子、食用海盐，低温盐焗，保质期12个月，是海鲜零食中高端的干货款。', 10, 5);
INSERT INTO `goods` VALUES (63, '蔓越莓软心饼干', '/picture/63-1.jpg', '/picture/63-2.jpg', '/picture/63-3.jpg', 18.9, '蔓越莓软心饼干外皮呈浅焦糖色，能看到暗红的蔓越莓果干嵌在其中，视觉上诱人十足。咬开时没有清脆声响，而是略带软糯的质感，嗅觉上蔓越莓的酸甜果香混合着黄油香气，清新不腻。触感外皮微酥，内芯软糯，入口先是黄油饼干的绵密，随即蔓越莓的酸甜在口腔中迸发，果干的嚼劲与饼干的软嫩融合，味觉上甜中带酸，层次丰富。主要原料：蔓越莓干、黄油、低筋面粉、糖粉，甜度：四星（满五星），保质期8个月，果干含量≥20%，是饼干系列中软心口感的代表，适合喜欢酸甜风味的人群。', 10, 1);
INSERT INTO `goods` VALUES (64, '阖家欢乐坚果礼盒', '/picture/64-1.jpg', '/picture/64-2.jpg', '/picture/64-3.jpg', 198.9, '阖家欢乐坚果礼盒外包装为中国红主色调，搭配金色祥云图案，视觉上喜庆大气，礼盒内包含巴旦木、夏威夷果、腰果、开心果、碧根果等8款坚果，独立罐装。开启礼盒时能听到礼盒盖的“啪”声，听觉上有仪式感，嗅觉上混合着各类坚果的醇香，浓郁不腻。触感礼盒质感厚实，坚果罐密封严实，每款坚果颗粒饱满酥脆，入口根据品类不同，或清甜或咸香，味觉上覆盖甜、咸、原味等多种风味，满足不同口味需求。所有坚果均采用低温烘焙工艺，无添加防腐剂，保质期12个月，是节日礼盒中经典的阖家分享款，适合春节、中秋等传统节日馈赠。', 10, 8);
INSERT INTO `goods` VALUES (65, '缤纷果干礼盒', '/picture/65-1.jpg', '/picture/65-2.jpg', '/picture/65-3.jpg', 168.9, '缤纷果干礼盒外包装为多彩渐变设计，视觉上活泼亮眼，礼盒内包含葡萄干、蔓越莓干、芒果干、草莓干、黄桃干等10款果干，独立小包装。开启时发出礼盒丝带的“嘶啦”声，听觉上有仪式感，嗅觉上混合着各类水果的香甜，清新自然。触感果干肉质饱满，软糯有嚼劲，入口根据品类不同，或酸甜或清甜，味觉上无添加人工香精，仅靠水果自然提味，甜度适中（二星至四星，满五星）。所有果干均采用冻干锁鲜工艺，保质期18个月，是节日礼盒中适合儿童与女性的清甜款。', 10, 8);
INSERT INTO `goods` VALUES (66, '年味肉食礼盒', '/picture/66-1.jpg', '/picture/66-2.jpg', '/picture/66-3.jpg', 258.9, '年味肉食礼盒外包装为复古国潮设计，视觉上年味十足，礼盒内包含酱牛肉、卤猪蹄、烤肠、熏鸡、香辣鸭脖等8款肉食，真空独立包装。开启时能听到真空包装的“啪”声，听觉上解压，嗅觉上混合着卤香、烤香等多种肉食香气，浓郁诱人。触感肉食肉质紧实，或酥烂或有嚼劲，入口根据品类不同，或咸香或麻辣，味觉上咸淡适中，风味浓郁且不腻。所有肉食均采用高温灭菌工艺，保质期9个月，是节日礼盒中适合家庭聚餐的硬菜款。', 10, 8);
INSERT INTO `goods` VALUES (67, '茶点饼干礼盒', '/picture/67-1.jpg', '/picture/67-2.jpg', '/picture/67-3.jpg', 158.9, '茶点饼干礼盒外包装为新中式设计，搭配水墨山水图案，视觉上雅致大气，礼盒内包含黄油曲奇、抹茶饼干、椰香薄脆、香葱苏打等10款饼干，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着黄油、奶香、茶香等多种香气，清新不腻。触感饼干或酥松或薄脆，入口根据品类不同，或香甜或咸香，味觉上甜度覆盖一星至四星（满五星），满足不同茶点需求。所有饼干均采用低温烘烤工艺，保质期10个月，是节日礼盒中适合品茶搭配的雅致款。', 10, 8);
INSERT INTO `goods` VALUES (68, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (69, '海鲜臻品礼盒', '/picture/69-1.jpg', '/picture/69-2.jpg', '/picture/69-3.jpg', 298.9, '海鲜臻品礼盒外包装为深海蓝主色调，视觉上高端大气，礼盒内包含烤虾、鱿鱼丝、鳗鱼丝、花蛤肉等8款海鲜零食，独立真空包装。开启时能听到真空包装的轻响，听觉上有质感，嗅觉上混合着海鲜的鲜香与烘烤香，清新无腥味。触感海鲜零食或柔韧或酥脆，入口根据品类不同，或鲜甜或麻辣，味觉上咸淡适中，保留海鲜的自然风味。所有海鲜均采用低温碳烤或高温灭菌工艺，保质期8-12个月不等，是节日礼盒中高端的海鲜特色款。', 10, 8);
INSERT INTO `goods` VALUES (70, '五谷杂粮礼盒', '/picture/70-1.jpg', '/picture/70-2.jpg', '/picture/70-3.jpg', 148.9, '五谷杂粮礼盒外包装为自然米色主色调，搭配谷物图案，视觉上健康质朴，礼盒内包含大米、小米、黑米、红豆、薏米等10款杂粮，独立密封罐装。开启时发出罐盖的“啪”声，听觉上解压，嗅觉上混合着各类谷物的清香，自然无异味。触感杂粮颗粒饱满，质地干燥，烹饪后口感或软糯或有嚼劲，入口根据品类不同，或清甜或清淡，味觉上无额外调味，保留谷物的自然风味。所有杂粮均无添加防腐剂，保质期18个月，是节日礼盒中适合馈赠长辈的健康款。', 10, 8);
INSERT INTO `goods` VALUES (72, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (73, '低糖健康礼盒', '/picture/73-1.jpg', '/picture/73-2.jpg', '/picture/73-3.jpg', 188.9, '低糖健康礼盒外包装为清新绿色主色调，视觉上健康自然，礼盒内包含无糖饼干、低糖坚果、无糖酸奶溶豆、杂粮脆片等10款低糖零食，独立包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着谷物香、奶香等清淡香气，无甜腻味。触感零食或酥松或酥脆，入口根据品类不同，或清淡或微甜，味觉上甜度均≤一星（满五星），无添加蔗糖。所有零食均采用健康工艺制作，保质期8-12个月不等，是节日礼盒中适合控糖人群的健康款。', 10, 8);
INSERT INTO `goods` VALUES (74, '环球零食礼盒', '/picture/74-1.jpg', '/picture/74-2.jpg', '/picture/74-3.jpg', 288.9, '环球零食礼盒外包装为多国风情设计，视觉上时尚大气，礼盒内包含进口饼干、巧克力、坚果、果干等12款全球特色零食，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各国零食的独特香气，层次丰富。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上覆盖不同国家的风味特色，甜度与咸度适中。所有零食均为正规进口，保质期6-12个月不等，是节日礼盒中适合年轻群体的时尚款。', 10, 8);
INSERT INTO `goods` VALUES (75, '进口黑金松露巧克力', '/picture/75-1.jpg', '/picture/75-2.jpg', '/picture/75-3.jpg', 198.9, '进口黑金松露巧克力呈深棕色的球形，表面裹有可可粉，视觉上哑光高级，单颗独立金箔包装。掰开时能听到巧克力脆皮的轻微脆响，听觉上柔和，嗅觉上浓郁的黑松露香气混合着可可的醇香，层次丰富且不腻。触感应指即融，内芯绵密丝滑，入口先是可可的微苦，随即黑松露的独特香气在口腔中散开，味觉上甜苦平衡（三星，满五星），可可含量≥70%，无添加代可可脂，回味悠长且有松露的独特回甘。主要原料：进口可可液块、黑松露粉、淡奶油，冷链运输保鲜，保质期6个月，是高端零食中巧克力控的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (76, '特级冻干榴莲干', '/picture/76-1.jpg', '/picture/76-2.jpg', '/picture/76-3.jpg', 168.9, '特级冻干榴莲干采用泰国金枕榴莲制作，呈淡黄色，视觉上果肉纹理清晰，无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的榴莲果香，纯正且无香精味。触感酥脆易嚼，入口即化，先是榴莲的香甜在舌尖散开，随即淡淡的奶香回味，味觉上甜而不腻（四星，满五星），冻干工艺保留90%以上榴莲营养，无添加蔗糖。主要原料：泰国金枕榴莲果肉，冻干锁鲜工艺，保质期12个月，独立密封包装，是高端零食中榴莲爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (77, '顶级鱼子酱薯片', '/picture/77-1.jpg', '/picture/77-2.jpg', '/picture/77-3.jpg', 228.9, '顶级鱼子酱薯片呈薄透的淡黄色，表面均匀附着鱼子酱与芝士粉，视觉上质感十足，单片独立包装。咬下时发出“啪”的清脆声响，听觉上解压，嗅觉上浓郁的鱼子酱咸香混合着芝士的奶香，醇厚诱人。触感薄脆易嚼，入口即化，先是鱼子酱的咸鲜在舌尖散开，随即芝士的醇香回味，味觉上咸甜平衡（二星，满五星），薯片采用非转基因马铃薯制作，无添加人工色素。主要原料：马铃薯片、鱼子酱、芝士粉、黄油，低温烘烤工艺，保质期8个月，是高端零食中轻奢的休闲款。', 10, 11);
INSERT INTO `goods` VALUES (78, '精选松茸坚果混合装', '/picture/78-1.jpg', '/picture/78-2.jpg', '/picture/78-3.jpg', 258.9, '精选松茸坚果混合装包含松茸碎、夏威夷果、碧根果、开心果等高端坚果，视觉上颗粒饱满，配色自然。混合时能听到坚果碰撞的轻微声响，听觉上解压，嗅觉上松茸的独特清香混合着坚果的醇香，层次独特。触感坚果酥脆，松茸碎绵软，入口先是坚果的醇香，随即松茸的清鲜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留食材自然风味。主要原料：精选松茸、进口坚果，低温烘焙工艺，保质期10个月，独立小包装，是高端零食中兼具营养与口感的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (79, '法式鹅肝酱饼干', '/picture/79-1.jpg', '/picture/79-2.jpg', '/picture/79-3.jpg', 188.9, '法式鹅肝酱饼干采用法式薄脆饼干搭配手工鹅肝酱，视觉上饼干金黄酥脆，鹅肝酱质地绵密。掰开饼干时发出“咔嚓”的脆响，听觉上清脆，嗅觉上鹅肝酱的浓郁醇香混合着饼干的黄油香，诱人食欲。触感饼干酥脆，鹅肝酱绵密，入口先是饼干的酥松，随即鹅肝酱的醇厚在口腔中散开，味觉上咸香适中（二星，满五星），无腥味，鹅肝酱含量≥40%。主要原料：法式薄脆饼干、新鲜鹅肝、黄油、食用盐，低温冷藏工艺，保质期6个月，是高端零食中法式风味的特色款。', 10, 11);
INSERT INTO `goods` VALUES (80, '冰岛即食海参', '/picture/80-1.jpg', '/picture/80-2.jpg', '/picture/80-3.jpg', 398.9, '冰岛即食海参呈深褐色，视觉上肉质厚实，参刺完整，独立真空包装。切开时能听到海参肉质的轻微“咯吱”声，听觉上有弹性，嗅觉上淡淡的海鲜咸香，无腥味。触感肉质Q弹有嚼劲，入口先是海参的鲜甜，随即淡淡的鲍汁提味（鲍汁款），味觉上咸淡适中（一星，满五星），无添加防腐剂，采用高温灭菌工艺锁鲜。主要原料：冰岛进口海参、鲍汁（可选），保质期12个月，开袋即食，是高端零食中滋补养生的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (81, '日式和牛脆片', '/picture/81-1.jpg', '/picture/81-2.jpg', '/picture/81-3.jpg', 268.9, '日式和牛脆片采用和牛雪花部位制作，呈浅棕色，视觉上纹理清晰，薄如蝉翼。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上和牛的醇香混合着日式照烧的甜香，浓郁不腻。触感薄脆易嚼，入口先是和牛的鲜香，随即照烧的甜咸在舌尖散开，味觉上甜咸平衡（三星，满五星），无添加人工香精，保留和牛的自然风味。主要原料：日式和牛、照烧酱、食用盐，低温烘烤工艺，保质期9个月，独立密封包装，是高端零食中肉食爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (82, '顶级白松露坚果酱', '/picture/82-1.jpg', '/picture/82-2.jpg', '/picture/82-3.jpg', 298.9, '顶级白松露坚果酱呈浅棕色，质地绵密，视觉上无颗粒感，玻璃罐装配金色瓶盖。搅拌时触感顺滑，听觉上无明显声响，嗅觉上白松露的独特清香混合着坚果的醇香，层次丰富。入口绵密顺滑，先是坚果的香甜在舌尖散开，随即白松露的清鲜回味，味觉上甜咸平衡（二星，满五星），可搭配面包、饼干食用，风味独特。主要原料：白松露粉、榛子仁、杏仁、黄油，低温熬煮工艺，保质期12个月，是高端零食中轻奢的佐餐款。', 10, 11);
INSERT INTO `goods` VALUES (83, '澳洲进口芒果干', '/picture/83-1.jpg', '/picture/83-2.jpg', '/picture/83-3.jpg', 158.9, '澳洲进口芒果干采用澳洲凯特芒制作，呈金黄色，视觉上果肉厚实，纹理清晰，无添加色素。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的芒果果香，纯正且无香精味。触感肉质饱满，软糯有嚼劲，不粘牙，入口先是芒果的清甜，随即淡淡的果酸提味，味觉上甜酸平衡（三星，满五星），无添加蔗糖，仅靠芒果自然提甜。主要原料：澳洲凯特芒果肉，冻干锁鲜工艺，保质期18个月，独立密封包装，是高端零食中果干类的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (84, '奢享鱼子酱巧克力', '/picture/84-1.jpg', '/picture/84-2.jpg', '/picture/84-3.jpg', 288.9, '奢享鱼子酱巧克力呈球形，外层为黑巧克力，内芯包裹鱼子酱夹心，视觉上黑金配色，高级感十足。咬开时能听到巧克力脆皮的脆响，听觉上满足，嗅觉上黑巧克力的微苦混合着鱼子酱的咸鲜，层次独特。触感外层酥脆，内芯绵密，入口先是黑巧克力的醇厚，随即鱼子酱的咸鲜在口腔中散开，味觉上甜咸平衡（二星，满五星），可可含量≥80%，鱼子酱为进口顶级款。主要原料：进口黑巧克力、顶级鱼子酱、淡奶油，冷链保鲜，保质期6个月，是高端零食中极具特色的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (85, '童趣零食礼盒', '/picture/68-1.jpg', '/picture/68-2.jpg', '/picture/68-3.jpg', 128.9, '童趣零食礼盒外包装为卡通萌趣设计，印有经典动画形象，视觉上吸引儿童，礼盒内包含动物饼干、星星软糖、鳕鱼肠、溶豆、磨牙棒等12款儿童零食，独立小包装。开启时发出礼盒丝带的轻响，听觉上活泼，嗅觉上混合着奶香、果香等清新香气，无刺鼻味。触感零食或酥松或软糯，专为儿童设计口感，入口根据品类不同，或清甜或咸香，味觉上甜度均≤三星（满五星），无添加人工色素与香精。所有零食均符合儿童食品标准，保质期6-18个月不等，是节日礼盒中适合馈赠有娃家庭的童趣款。', 10, 8);
INSERT INTO `goods` VALUES (86, '草莓味磨牙棒', '/picture/35-1.jpg', '/picture/35-2.jpg', '/picture/35-3.jpg', 18.9, '草莓味磨牙棒呈长条状，视觉上淡粉色（天然草莓粉调色），表面有细密的纹理，适合儿童抓握磨牙。咬嚼时发出轻微的“咯吱”声，听觉上温和，嗅觉上淡淡的草莓果香混合着小麦的清香，清新不腻。触感坚硬但不硌牙，专为出牙期宝宝设计，能缓解牙龈不适，入口先是草莓的清甜，随即小麦的醇香散开，味觉上甜度极低（一星，满五星），无添加香精色素。主要原料：小麦粉、草莓粉、奶粉、橄榄油，保质期12个月，独立包装，干净卫生，是儿童零食中针对性的磨牙款。', 10, 3);
INSERT INTO `goods` VALUES (87, '咖啡伴侣礼盒', '/picture/71-1.jpg', '/picture/71-2.jpg', '/picture/71-3.jpg', 178.9, '咖啡伴侣礼盒外包装为简约轻奢设计，视觉上高级感十足，礼盒内包含各类口味曲奇、焦糖饼干、坚果仁、巧克力等8款搭配咖啡的零食，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着咖啡香（附赠挂耳咖啡）、奶香、焦糖香等，浓郁不腻。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上甜度覆盖二星至四星（满五星），与咖啡搭配口感互补。所有零食均采用低温工艺制作，保质期9-12个月不等，是节日礼盒中适合咖啡爱好者的轻奢款。', 10, 8);
INSERT INTO `goods` VALUES (88, '香蕉味泡芙球', '/picture/36-1.jpg', '/picture/36-2.jpg', '/picture/36-3.jpg', 22.9, '香蕉味泡芙球呈淡黄色的中空球状，视觉上小巧可爱，表面有细密的气孔，适合儿童抓食。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的香蕉果香混合着奶香，清新自然。触感空心酥脆，入口即化，先是香蕉的清甜在舌尖散开，随即奶香回味，味觉上甜度适中（二星，满五星），无添加人工香精。主要原料：香蕉泥、奶粉、小麦粉、植物油，保质期8个月，非油炸工艺，是儿童零食中口感轻盈的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (89, '精选羊肚菌脆片', '/picture/85-1.jpg', '/picture/85-2.jpg', '/picture/85-3.jpg', 218.9, '精选羊肚菌脆片采用云南特级羊肚菌制作，呈深褐色，视觉上菌纹清晰，完整无碎。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上羊肚菌的独特清香混合着淡淡的海盐香，清新自然。触感酥脆易嚼，入口先是羊肚菌的清鲜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工调味，冻干工艺保留羊肚菌营养。主要原料：云南特级羊肚菌、食用海盐，冻干工艺，保质期10个月，独立包装，是高端零食中兼具营养与口感的特色款。', 10, 11);
INSERT INTO `goods` VALUES (90, '蓝莓味果泥', '/picture/37-1.jpg', '/picture/37-2.jpg', '/picture/37-3.jpg', 21.9, '蓝莓味果泥呈深紫色的泥状，视觉上质地细腻无颗粒，包装为便携吸嘴袋，方便儿童食用。挤压时触感顺滑，听觉上无明显声响，嗅觉上浓郁的蓝莓果香，清新不刺鼻，无香精味。入口绵密顺滑，无需咀嚼，先是蓝莓的酸甜在舌尖散开，随即水果的自然清甜回味，味觉上无添加蔗糖（一星，满五星），仅靠蓝莓自然提甜。主要原料：蓝莓果肉（≥90%）、苹果泥、维生素C，保质期12个月，无防腐剂，是儿童零食中补充花青素的营养款。', 10, 3);
INSERT INTO `goods` VALUES (91, '五香开口松子', '/picture/46-1.jpg', '/picture/46-2.jpg', '/picture/46-3.jpg', 69.9, '五香开口松子外壳呈棕红色，开口均匀，视觉上颗粒饱满修长，果仁呈淡黄色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上浓郁的五香料香混合着松子的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是五香的咸香，随即松子的清甜散开，味觉上咸淡适中（二星，满五星），五香味浓郁且不掩盖松子本身的香气，越嚼越有回甘。主要原料：松子、五香粉、食用盐，低温烘焙，保质期8个月，无添加香精，是坚果系列中咸香风味的特色款。', 10, 4);
INSERT INTO `goods` VALUES (92, '孜然味烤鱿鱼板', '/picture/61-1.jpg', '/picture/61-2.jpg', '/picture/61-3.jpg', 47.9, '孜然味烤鱿鱼板呈深棕色，表面有孜然颗粒的均匀分布，视觉上板状完整，厚度均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上孜然的辛香混合着鱿鱼的鲜香，独特诱人。触感柔韧有嚼劲，入口先是鱿鱼的鲜甜，随即孜然的咸香在舌尖散开，味觉上咸淡适中（二星，满五星），孜然味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼板、孜然粉、食用盐、白砂糖，碳烤工艺，保质期9个月，是海鲜零食中孜然风味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (93, '芝士咸味饼干', '/picture/1768183025317.jpg', '/picture/1768183025334.jpg', '/picture/1768183025348.jpg', 19.9, '芝士咸味饼干呈淡黄色，表面有芝士粉的均匀附着，视觉上质感十足。轻咬时发出清脆的脆响，嗅觉上浓郁的芝士咸香混合着黄油香气，诱人食欲。触感酥脆不粘牙，入口先是芝士的咸香醇厚，随即黄油的绵密感在舌尖散开，味觉上咸度适中，还带着芝士特有的微酸回甘，层次丰富。主要原料：芝士粉、黄油、小麦粉、食用盐，甜度：一星（满五星），保质期10个月，芝士含量≥15%，是饼干系列中咸味芝士控的必选款。', 10, 1);
INSERT INTO `goods` VALUES (94, '番茄味薯片脆', '/picture/1768183053016.jpg', '/picture/1768183053030.jpg', '/picture/1768183053075.jpg', 7.9, '番茄味薯片脆呈薄透的橙红色，表面裹满番茄粉，视觉上色彩鲜亮。咬下时发出清脆的“啪”声，听觉上解压十足，嗅觉上浓郁的番茄酸甜果香混合着土豆香，清新不腻。触感薄脆易嚼，入口即化，先是番茄的酸甜在舌尖迸发，随即土豆的醇香回味，味觉上酸甜平衡，番茄味浓郁且不齁甜。主要原料：马铃薯片、番茄粉、白砂糖、食用盐，保质期10个月，薄切烘烤工艺，低脂低油，是膨化系列中经典的番茄风味款。', 11, 2);
INSERT INTO `goods` VALUES (95, '原味鲜虾片', '/picture/1768183083877.jpg', '/picture/1768183083891.jpg', '/picture/11-3.jpg', 23.9, '原味鲜虾片呈薄透的淡粉色，视觉上轻盈通透，能看到细微的虾粉颗粒。咬下时发出清脆的“啪”声，听觉上解压有趣，嗅觉上浓郁的鲜虾鲜香，清新无腥味。触感薄脆易嚼，入口即化，先是鲜虾的鲜甜在舌尖散开，随即淡淡的盐味提味，味觉上咸淡适中（一星，满五星），无添加人工香精。主要原料：虾粉（≥40%）、小麦粉、食用盐、植物油，保质期9个月，非油炸烘烤，是儿童零食中补充优质蛋白的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (96, '柠檬味烤鱼片', '/picture/1768183098288.jpg', '/picture/12-2.jpg', '/picture/12-3.jpg', 44.9, '柠檬味烤鱼片呈淡黄色，视觉上质地轻薄，纹理清晰。咬下时发出轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上柠檬的清香混合着鱼肉的鲜香，清新不腻。触感柔韧有嚼劲，入口先是柠檬的酸甜，随即鱼肉的鲜甜散开，味觉上酸甜平衡（二星，满五星），柠檬味掩盖了鱼肉的腥味，口感更清新。主要原料：马面鱼、柠檬汁、食用盐、白砂糖，低温烘烤，保质期10个月，是海鲜零食中清新风味的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (97, '抹茶红豆夹心饼干', '/picture/1768183115678.jpg', '/picture/13-2.jpg', '/picture/13-3.jpg', 16.9, '抹茶红豆夹心饼干外层是淡绿色的抹茶饼干体，中间夹着暗红色的红豆沙夹心，视觉上配色清新雅致。掰开时能听到饼干体轻微的脆响，夹心则软糯拉丝，嗅觉上宇治抹茶的清苦香气混合着红豆的甜香，淡雅宜人。触感外层酥脆，夹心绵密，入口先是抹茶的清苦，随即红豆夹心的香甜中和苦味，味觉上甜苦平衡，还带着抹茶特有的茶韵回甘。主要原料：宇治抹茶粉、红豆沙、小麦粉、黄油，甜度：三星（满五星），保质期9个月，无人工色素，是饼干系列中兼具日式风味的特色款。', 10, 1);
INSERT INTO `goods` VALUES (98, '海盐焦糖饼干', '/picture/1768183141942.jpg', '/picture/14-2.jpg', '/picture/14-3.jpg', 14.9, '海盐焦糖饼干呈焦糖色，表面有细密的盐粒点缀，视觉上光泽诱人。轻咬时发出清脆的“咔嚓”声，嗅觉上浓郁的焦糖香气混合着淡淡的海盐气息，甜咸交织。触感酥脆易断，入口先是焦糖的焦香甜味，随即海盐的咸香在舌尖散开，中和甜腻，味觉上回味有淡淡的黄油香，层次丰富。主要原料：焦糖酱、食用海盐、小麦粉、黄油，甜度：四星（满五星），保质期10个月，采用低温烘烤工艺，是饼干系列中甜咸风味的热门款。', 10, 1);
INSERT INTO `goods` VALUES (99, '花生酱夹心饼干', '/picture/15-1.jpg', '/picture/15-2.jpg', '/picture/15-3.jpg', 13.9, '花生酱夹心饼干外层是金黄色的酥性饼干，中间夹着醇厚的花生酱夹心，视觉上饱满厚实。掰开时能听到饼干的脆响，同时花生酱夹心会微微拉丝，嗅觉上浓郁的花生烘烤香气扑面而来，醇厚不腻。触感外层酥脆，夹心绵密，入口先是饼干的酥松，随即花生酱的咸香与微甜在口腔中散开，味觉上花生味浓郁，还带着一丝烘烤的焦香。主要原料：花生酱、小麦粉、黄油、白砂糖，甜度：三星（满五星），保质期9个月，花生酱含量≥30%，是饼干系列中经典的咸甜夹心款。', 10, 1);
INSERT INTO `goods` VALUES (100, '椰香薄脆饼干', '/picture/16-1.jpg', '/picture/16-2.jpg', '/picture/16-3.jpg', 11.9, '椰香薄脆饼干呈薄透的奶白色，能看到细密的椰蓉颗粒，视觉上轻盈通透。咬下时发出清脆的“咔嚓”声，嗅觉上浓郁的椰香混合着小麦的清香，清新自然。触感薄脆易嚼，入口即化，先是椰蓉的香甜在舌尖散开，随即小麦的醇香回味，味觉上甜而不腻，椰香浓郁且持久。主要原料：椰蓉、小麦粉、黄油、椰奶，甜度：二星（满五星），保质期11个月，采用薄切烘烤工艺，是饼干系列中口感轻盈的休闲款。', 10, 1);
INSERT INTO `goods` VALUES (101, '紫薯燕麦饼干', '/picture/17-1.jpg', '/picture/17-2.jpg', '/picture/17-3.jpg', 17.9, '紫薯燕麦饼干呈淡紫色，嵌有燕麦片的颗粒，视觉上健康自然。掰开时能听到燕麦片与饼干体碰撞的轻微声响，嗅觉上紫薯的香甜混合着燕麦的谷物香气，清淡不腻。触感酥松中带着燕麦的嚼劲，入口先是紫薯的清甜，随即燕麦的谷物香在口腔中散开，味觉上低糖低脂，口感丰富，还带着一丝谷物的回甘。主要原料：紫薯泥、燕麦片、小麦粉、橄榄油，甜度：一星（满五星），保质期8个月，无添加蔗糖，是饼干系列中健康代餐的优选款。', 10, 1);
INSERT INTO `goods` VALUES (102, '黄油奶香曲奇饼干', '/picture/18-1.jpg', '/picture/18-2.jpg', '/picture/18-3.jpg', 12.9, '这款黄油奶香曲奇饼干呈诱人的金黄色，表面分布着细密的黄油颗粒，视觉上层次分明。掰开时能听到清脆的“咔嚓”声，瞬间释放出浓郁的黄油与奶香交织的醇厚香气，嗅觉上让人垂涎欲滴。触感应指即碎，酥松不粘牙，入口先是黄油的绵密醇厚，紧接着是淡淡奶香在舌尖散开，甜而不腻，尾调还带着一丝天然的香草气息，味觉体验丰富。主要原料选用新西兰黄油、高筋小麦粉、进口奶粉，甜度：三星（满五星），保质期长达12个月，独立小包装设计，无论是下午茶搭配咖啡，还是日常解馋都十分合适，是饼干系列中经典的奶香风味代表作。', 10, 1);
INSERT INTO `goods` VALUES (103, '红豆薏米饼干', '/picture/19-1.jpg', '/picture/19-2.jpg', '/picture/19-3.jpg', 15.9, '红豆薏米饼干呈浅棕色，能看到红豆与薏米的颗粒，视觉上健康质朴。掰开时发出轻微的酥响，嗅觉上红豆的香甜混合着薏米的谷物清香，淡雅宜人。触感酥松易嚼，入口先是谷物的醇香，随即红豆的清甜散开，味觉上低糖清淡，还带着薏米的微甘，饱腹感强。主要原料：红豆粉、薏米粉、小麦粉、植物油，甜度：一星（满五星），保质期9个月，无添加防腐剂，是饼干系列中主打健康养生的特色款。', 10, 1);
INSERT INTO `goods` VALUES (104, '原味空心薯笛', '/picture/20-1.jpg', '/picture/20-2.jpg', '/picture/20-3.jpg', 8.9, '原味空心薯笛呈金黄的中空管状，表面有细密的纹理，视觉上酥脆诱人。咬下时发出“咔嚓”的清脆声响，听觉上极具解压感，嗅觉上浓郁的土豆原香扑面而来，清新自然。触感空心酥脆，轻捏即碎，入口先是土豆的醇香，随即淡淡的盐味提味，味觉上咸淡适中，薯香浓郁且不油腻，越嚼越有谷物的回甘。主要原料：马铃薯粉、玉米淀粉、食用盐、棕榈油，保质期9个月，采用非油炸膨化工艺，低脂轻卡，是膨化系列中经典的原味休闲款，适合全家共享。', 10, 2);
INSERT INTO `goods` VALUES (105, '烧烤味玉米浪', '/picture/21-1.jpg', '/picture/21-2.jpg', '/picture/21-3.jpg', 9.9, '烧烤味玉米浪呈波浪形的金黄色，表面均匀附着烧烤调味料，视觉上色泽诱人。咬开时发出“咔嚓”的脆响，听觉上清脆悦耳，嗅觉上浓郁的烧烤香料香混合着玉米的清甜，层次丰富。触感波浪形的酥脆质感，入口先是玉米的香甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡，还带着一丝烟熏的香气，回味悠长。主要原料：玉米粉、烧烤调味料、植物油、白砂糖，保质期8个月，非油炸工艺，是膨化系列中风味浓郁的热门款。', 10, 2);
INSERT INTO `goods` VALUES (106, '黑巧克力榛子饼干', '/picture/22-1.jpg', '/picture/22-2.jpg', '/picture/22-3.jpg', 15.9, '黑巧克力榛子饼干通体呈深棕色调，嵌有饱满的榛子碎，视觉上极具质感。轻咬时能听到巧克力脆皮与饼干酥层碰撞的脆响，嗅觉上立刻捕捉到微苦的黑巧克力香与烘烤榛子的坚果香气，层次丰富。触感酥脆中带着榛子的微硬颗粒感，入口先是黑巧克力的微苦醇厚，随即榛子的香脆与饼干的酥松融合，甜苦平衡，味觉上回味悠长。主要原料：可可含量70%的黑巧克力、榛子仁、低筋面粉、黄油，甜度：二星（满五星），保质期10个月，不含反式脂肪酸，是饼干系列中兼具巧克力风味与坚果口感的特色款。', 10, 1);
INSERT INTO `goods` VALUES (107, '海苔味米饼', '/picture/23-1.jpg', '/picture/23-2.jpg', '/picture/23-3.jpg', 10.9, '海苔味米饼呈米白色，表面有海苔碎的均匀分布，视觉上清新素雅。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上海苔的鲜咸香气混合着大米的清香，淡雅宜人。触感酥脆中带着大米的蓬松感，入口先是大米的醇香，随即海苔的鲜咸散开，味觉上咸淡适中，还带着一丝米香的回甘，口感轻盈不腻。主要原料：大米粉、海苔碎、食用盐、植物油，保质期12个月，非油炸膨化，是膨化系列中适合儿童的清淡款。', 10, 2);
INSERT INTO `goods` VALUES (108, '香辣味虾条', '/picture/24-1.jpg', '/picture/24-2.jpg', '/picture/24-3.jpg', 11.9, '香辣味虾条呈橙红色的长条状，表面裹满香辣调味料，视觉上色泽诱人。咬下时发出“咔嚓”的脆响，听觉上极具满足感，嗅觉上浓郁的虾香混合着辣椒的辛香，香气扑鼻。触感酥脆不粘牙，入口先是鲜虾的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中，咸香入味，虾味浓郁且持久。主要原料：虾粉、小麦粉、辣椒面、植物油，保质期8个月，虾粉含量≥15%，是膨化系列中重口味爱好者的优选款。', 10, 2);
INSERT INTO `goods` VALUES (109, '芝士味空心脆', '/picture/25-1.jpg', '/picture/25-2.jpg', '/picture/25-3.jpg', 13.9, '芝士味空心脆呈淡黄色的中空球状，表面有芝士粉的附着，视觉上呆萌可爱。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的芝士咸香混合着奶香，醇厚诱人。触感空心酥脆，入口即碎，先是芝士的咸香在口腔中散开，随即奶香回味，味觉上咸甜平衡，芝士味浓郁且不腻。主要原料：芝士粉、小麦粉、黄油、食用盐，保质期9个月，非油炸工艺，是膨化系列中芝士控的必选款。', 10, 2);
INSERT INTO `goods` VALUES (110, '芥末味青豆脆', '/picture/26-1.jpg', '/picture/26-2.jpg', '/picture/26-3.jpg', 12.9, '芥末味青豆脆呈翠绿色，包裹着淡淡的芥末调味粉，视觉上清新亮眼。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上芥末的微辛香气混合着青豆的清香，层次独特。触感酥脆中带着青豆的颗粒感，入口先是青豆的清甜，随即芥末的微辛在舌尖散开，味觉上辛而不辣，咸香入味，越嚼越有青豆的回甘。主要原料：青豆、芥末粉、食用盐、植物油，保质期10个月，低温膨化工艺，是膨化系列中风味独特的小众款。', 10, 2);
INSERT INTO `goods` VALUES (111, '蜂蜜黄油味薯条', '/picture/27-1.jpg', '/picture/27-2.jpg', '/picture/27-3.jpg', 14.9, '蜂蜜黄油味薯条呈金黄的长条状，表面裹满蜂蜜黄油酱，视觉上光泽诱人。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的黄油香混合着蜂蜜的甜香，甜而不腻。触感酥脆中带着微微的绵密感，入口先是黄油的醇厚，随即蜂蜜的清甜散开，味觉上甜咸平衡，黄油味浓郁且回味有奶香。主要原料：马铃薯条、黄油、蜂蜜、食用盐，保质期8个月，非油炸烘烤，是膨化系列中甜咸风味的热门款。', 10, 2);
INSERT INTO `goods` VALUES (112, '藤椒味洋芋片', '/picture/28-1.jpg', '/picture/28-2.jpg', '/picture/28-3.jpg', 10.9, '藤椒味洋芋片呈薄透的淡黄色，表面有藤椒粉的均匀附着，视觉上清爽质朴。咬下时发出“啪”的清脆声响，听觉上解压有趣，嗅觉上藤椒的麻香混合着土豆的清香，独特诱人。触感薄脆易嚼，入口先是土豆的醇香，随即藤椒的麻香在舌尖散开，味觉上麻而不苦，咸香入味，还带着一丝藤椒的清鲜。主要原料：马铃薯片、藤椒粉、食用盐、植物油，保质期9个月，薄切工艺，是膨化系列中川味特色的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (113, '肉松味米卷', '/picture/29-1.jpg', '/picture/29-2.jpg', '/picture/29-3.jpg', 15.9, '肉松味米卷呈米白色的卷状，表面裹满肉松碎，视觉上饱满诱人。咬开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上肉松的咸香混合着大米的清香，浓郁不腻。触感外层酥脆，内芯蓬松，入口先是肉松的咸香，随即大米的醇香散开，味觉上咸甜适中，肉松味浓郁且有嚼劲。主要原料：大米粉、肉松、白砂糖、食用盐，保质期12个月，非油炸膨化，是膨化系列中饱腹感强的代餐款。', 10, 2);
INSERT INTO `goods` VALUES (114, '海盐味豌豆脆', '/picture/30-1.jpg', '/picture/30-2.jpg', '/picture/30-3.jpg', 11.9, '海盐味豌豆脆呈淡绿色，表面有细密的海盐颗粒，视觉上清新自然。咬下时发出“咔嚓”的脆响，听觉上解压十足，嗅觉上豌豆的清香混合着海盐的咸香，清淡不腻。触感酥脆易嚼，入口先是豌豆的清甜，随即海盐的咸香提味，味觉上咸淡适中，豌豆味浓郁且回甘持久。主要原料：豌豆粉、食用海盐、植物油、玉米淀粉，保质期10个月，非油炸工艺，是膨化系列中健康轻卡的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (115, '香葱咸味苏打饼干', '/picture/31-1.jpg', '/picture/31-2.jpg', '/picture/31-3.jpg', 9.8, '香葱咸味苏打饼干呈奶白色基底，点缀着翠绿的香葱碎，视觉上清新自然。掰开时发出“啪”的清脆声响，嗅觉上浓郁的香葱香气混合着小麦的清香扑面而来，咸香不刺鼻。触感干爽不粘手，酥松易嚼，入口先是淡淡的小麦香，紧接着香葱的鲜咸在舌尖散开，口感清爽不腻，味觉上咸度适中，还带着苏打饼干特有的微碱性回甘。主要原料：小麦粉、香葱、食用纯碱、食用盐，甜度：一星（满五星），保质期9个月，无额外添加蔗糖，适合控糖人群，是饼干系列中经典的咸味休闲款。', 10, 1);
INSERT INTO `goods` VALUES (116, '水果味星星软糖', '/picture/32-1.jpg', '/picture/32-2.jpg', '/picture/32-3.jpg', 19.9, '水果味星星软糖呈五彩的星星造型，视觉上色彩鲜艳（采用天然果蔬色素），颗颗饱满晶莹，萌趣十足。捏动时触感Q弹软糯，无硬芯，听觉上无明显声响，嗅觉上浓郁的草莓、橙子、葡萄等混合水果果香，清新不刺鼻。入口软糯有嚼劲，不粘牙，先是草莓的酸甜在舌尖散开，随即橙子的清香、葡萄的清甜依次迸发，味觉上甜度适中（二星，满五星），无添加人工香精与防腐剂。主要原料：麦芽糖浆、天然果蔬汁、明胶、维生素C，保质期18个月，每颗独立包装，干净卫生，是儿童零食中补充维生素的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (117, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (118, '原味溶豆（酸奶味）', '/picture/34-1.jpg', '/picture/34-2.jpg', '/picture/34-3.jpg', 29.9, '酸奶味溶豆呈迷你的小颗粒状，视觉上奶白色，蓬松轻盈，造型小巧适合儿童抓握。轻捏即碎，触感绵软，听觉上无明显声响，嗅觉上浓郁的酸奶奶香，清新自然。入口即溶，无需咀嚼，先是酸奶的酸甜在舌尖化开，随即奶香回味，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠酸奶自然提味。主要原料：酸奶、奶粉、玉米淀粉、益生菌，保质期6个月，冻干工艺锁鲜，是儿童零食中适合低龄宝宝的辅食款。', 10, 3);
INSERT INTO `goods` VALUES (119, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (120, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (121, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (122, '芝士味小馒头', '/picture/38-1.jpg', '/picture/38-2.jpg', '/picture/38-3.jpg', 17.9, '芝士味小馒头呈迷你的奶黄色球状，视觉上小巧圆润，适合儿童抓握食用。咬下时发出轻微的“咔嚓”声，听觉上温和，嗅觉上浓郁的芝士香混合着奶香，醇厚不腻。触感酥松易嚼，入口即化，先是芝士的咸香在舌尖散开，随即奶香回味，味觉上咸甜适中（二星，满五星），无添加人工色素。主要原料：奶粉、芝士粉、小麦粉、鸡蛋，保质期10个月，独立小包装，是儿童零食中经典的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (123, '芒果味QQ糖', '/picture/39-1.jpg', '/picture/39-2.jpg', '/picture/39-3.jpg', 15.9, '芒果味QQ糖呈芒果形状的半透明状，视觉上金黄诱人，造型逼真可爱。捏动时触感Q弹有弹性，听觉上无明显声响，嗅觉上浓郁的芒果果香，清新自然无异味。入口软糯有嚼劲，不粘牙，先是芒果的清甜在舌尖散开，随即淡淡的果酸提味，味觉上甜度适中（三星，满五星），采用天然芒果汁调色调味。主要原料：麦芽糖浆、芒果汁、明胶、柠檬酸，保质期18个月，独立包装，是儿童零食中趣味十足的糖果款。', 10, 3);
INSERT INTO `goods` VALUES (124, '鳕鱼肠（芝士味）', '/picture/40-1.jpg', '/picture/40-2.jpg', '/picture/40-3.jpg', 25.9, '芝士味鳕鱼肠呈奶白色的长条状，视觉上质地均匀，无杂质，包装上印有卡通图案，吸引儿童。咬开时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的鳕鱼鲜香混合着芝士的咸香，醇厚不腻。触感弹嫩有嚼劲，专为儿童设计的软嫩口感，入口先是鳕鱼的鲜甜，随即芝士的咸香在口腔中散开，味觉上咸淡适中，无腥味，芝士味浓郁且自然。主要原料：鳕鱼肉（≥60%）、芝士粉、鸡蛋、食用盐，保质期9个月，独立真空包装，开袋即食，是儿童零食中补充优质蛋白的营养款。', 10, 3);
INSERT INTO `goods` VALUES (125, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (126, '原味手剥巴旦木', '/picture/42-1.jpg', '/picture/42-2.jpg', '/picture/42-3.jpg', 39.9, '原味手剥巴旦木外壳呈浅棕色，带有自然的纹理，视觉上饱满厚实，果仁呈奶白色，颗粒均匀。剥开外壳时能听到轻微的“咔嚓”声，听觉上解压，嗅觉上浓郁的巴旦木坚果原香，清淡不腻。触外壳坚硬但易剥，果仁触感饱满酥脆，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无额外调味（一星，满五星），仅靠巴旦木自然的咸香，越嚼越香，回甘持久。主要原料：精选巴旦木，无添加任何调味料，保质期12个月，低温烘焙锁鲜，是坚果系列中保留原味的经典款，富含优质脂肪与维生素E。', 10, 4);
INSERT INTO `goods` VALUES (127, '盐焗夏威夷果', '/picture/43-1.jpg', '/picture/43-2.jpg', '/picture/43-3.jpg', 59.9, '盐焗夏威夷果外壳呈棕褐色，带有天然的纹理，配有开果器，视觉上颗粒饱满圆润。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的坚果香混合着淡淡的海盐气息，咸香诱人。触感果仁绵密酥脆，入口先是海盐的咸香提味，随即夏威夷果特有的奶香在口腔中散开，味觉上咸甜平衡（二星，满五星），口感绵密且不腻，越嚼越有奶香回甘。主要原料：夏威夷果、食用海盐，低温烘焙，保质期10个月，无添加防腐剂，是坚果系列中口感绵密的高端款。', 10, 4);
INSERT INTO `goods` VALUES (128, '炭烧腰果', '/picture/44-1.jpg', '/picture/44-2.jpg', '/picture/44-3.jpg', 45.9, '炭烧腰果呈焦糖色，表面有细密的炭烧纹理，视觉上色泽诱人，颗粒饱满无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的炭烧香混合着腰果的坚果香，层次丰富。触感酥脆不粘牙，入口先是炭烧的焦香，随即腰果的清甜散开，味觉上咸甜适中（三星，满五星），炭烧味浓郁且不糊，回味有坚果的醇香。主要原料：腰果、白砂糖、食用盐、植物油，低温炭烧工艺，保质期11个月，是坚果系列中风味独特的热门款。', 10, 4);
INSERT INTO `goods` VALUES (129, '蜂蜜琥珀核桃仁', '/picture/45-1.jpg', '/picture/45-2.jpg', '/picture/45-3.jpg', 38.9, '蜂蜜琥珀核桃仁呈透亮的焦糖色，包裹着一层薄蜜，视觉上光泽诱人，核桃仁完整无碎。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的蜂蜜甜香混合着核桃的坚果香，甜而不腻。触感酥脆中带着微微的粘糯，入口先是蜂蜜的清甜，随即核桃的醇香在舌尖散开，味觉上甜咸平衡（四星，满五星），蜂蜜味浓郁且不齁甜，核桃的苦涩感被中和得恰到好处。主要原料：核桃仁、蜂蜜、白砂糖、白芝麻，低温熬煮挂浆，保质期9个月，是坚果系列中甜口的经典款。', 10, 4);
INSERT INTO `goods` VALUES (130, '原味碧根果', '/picture/47-1.jpg', '/picture/47-2.jpg', '/picture/47-3.jpg', 55.9, '原味碧根果外壳呈浅棕色，带有自然的裂纹，视觉上果仁饱满，易剥取。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的碧根果坚果香，清淡不腻，无额外调味。触感果仁酥脆绵密，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无添加（一星，满五星），仅靠碧根果自然的咸香，口感绵密且回味悠长。主要原料：精选碧根果，低温烘焙，保质期12个月，是坚果系列中保留原味的高端款，富含不饱和脂肪酸。', 10, 4);
INSERT INTO `goods` VALUES (131, '香辣花生', '/picture/48-1.jpg', '/picture/48-2.jpg', '/picture/48-3.jpg', 19.9, '香辣花生呈红棕色，表面裹满香辣调味料，视觉上色泽鲜亮，颗粒饱满无瘪粒。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的辣椒香混合着花生的烘烤香，香气扑鼻。触感酥脆不粘牙，入口先是花生的香甜，随即香辣味在舌尖散开，味觉上辣度适中（三星，满五星），咸香入味，花生的醇香与辣椒的辛香融合恰到好处。主要原料：花生、辣椒面、花椒粉、食用盐，低温烘烤，保质期10个月，是坚果系列中重口味的平价款。', 10, 4);
INSERT INTO `goods` VALUES (132, '抹茶味杏仁', '/picture/49-1.jpg', '/picture/49-2.jpg', '/picture/49-3.jpg', 42.9, '抹茶味杏仁呈淡绿色，表面均匀附着抹茶粉，视觉上清新雅致，杏仁颗粒完整。咬下时发出“咔嚓”的脆响，听觉上清脆，嗅觉上宇治抹茶的清苦香气混合着杏仁的坚果香，层次独特。触感酥脆易嚼，入口先是抹茶的清苦，随即杏仁的清甜散开，味觉上甜苦平衡（二星，满五星），抹茶味浓郁且不涩，杏仁的醇香回味持久。主要原料：杏仁、宇治抹茶粉、白砂糖、植物油，低温烘焙，保质期9个月，是坚果系列中风味新颖的特色款。', 10, 4);
INSERT INTO `goods` VALUES (133, '盐焗开心果', '/picture/50-1.jpg', '/picture/50-2.jpg', '/picture/50-3.jpg', 68.9, '盐焗开心果外壳呈淡绿色，开口率≥95%，视觉上颗粒饱满，果仁呈翠绿色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上淡淡的海盐香混合着开心果的坚果香，清新自然。触感果仁酥脆有嚼劲，入口先是海盐的咸香提味，随即开心果的清甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留开心果的自然风味。主要原料：开心果、食用海盐，低温烘焙，保质期11个月，是坚果系列中健康轻盐的高端款。', 10, 4);
INSERT INTO `goods` VALUES (134, '椰香腰果', '/picture/51-1.jpg', '/picture/51-2.jpg', '/picture/51-3.jpg', 48.9, '椰香腰果呈奶白色，表面裹满椰蓉，视觉上蓬松诱人，颗粒饱满。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上浓郁的椰香混合着腰果的坚果香，清新不腻。触感酥脆中带着椰蓉的绵软，入口先是椰蓉的香甜，随即腰果的醇香散开，味觉上甜而不腻（三星，满五星），椰香浓郁且持久，腰果的口感丰富有层次。主要原料：腰果、椰蓉、白砂糖、黄油，低温烘焙，保质期10个月，是坚果系列中甜口的特色款。', 10, 4);
INSERT INTO `goods` VALUES (135, '椒盐核桃', '/picture/52-1.jpg', '/picture/52-2.jpg', '/picture/52-3.jpg', 29.9, '椒盐核桃外壳呈深棕色，带有椒盐的均匀附着，视觉上纹理清晰，易剥开。撬开外壳时发出“啪”的轻响，听觉上解压，嗅觉上椒盐的咸香混合着核桃的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是椒盐的咸香，随即核桃的醇香散开，味觉上咸淡适中（二星，满五星），椒盐味掩盖了核桃的苦涩，口感更易接受。主要原料：核桃、椒盐粉、食用盐，低温烘焙，保质期12个月，是坚果系列中平价且风味佳的经典款。', 10, 4);
INSERT INTO `goods` VALUES (136, '原味碳烤鱿鱼丝', '/picture/53-1.jpg', '/picture/53-2.jpg', '/picture/53-3.jpg', 45.9, '原味碳烤鱿鱼丝呈深棕色，纹理清晰，视觉上丝丝分明，无碎渣。撕扯时能听到轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上浓郁的碳烤鱿鱼香，混合着淡淡的海鲜咸香，无腥味。触感柔韧有嚼劲，不粘牙，入口先是鱿鱼的鲜甜，随即碳烤的焦香在舌尖散开，味觉上咸淡适中（二星，满五星），无添加人工香精，仅靠鱿鱼本身的鲜味提味，越嚼越有海鲜的回甘。主要原料：新鲜鱿鱼、食用盐、白砂糖，碳烤工艺锁鲜，保质期9个月，独立真空包装，是海鲜零食中经典的手撕休闲款。', 10, 5);
INSERT INTO `goods` VALUES (137, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (138, '原味即食烤虾', '/picture/55-1.jpg', '/picture/55-2.jpg', '/picture/55-3.jpg', 68.9, '原味即食烤虾呈淡红色，视觉上虾身完整，个头均匀，肉质紧实。咬开时发出“咔嚓”的脆响（虾壳），听觉上满足，嗅觉上浓郁的鲜虾烘烤香，清新无腥味。触感虾壳酥脆，虾肉紧实有嚼劲，入口先是虾壳的咸香，随即虾肉的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留鲜虾的自然风味。主要原料：新鲜海虾、食用盐，低温碳烤，保质期10个月，独立包装，是海鲜零食中高蛋白的健康款。', 10, 5);
INSERT INTO `goods` VALUES (139, '烧烤味鱿鱼须', '/picture/56-1.jpg', '/picture/56-2.jpg', '/picture/56-3.jpg', 49.9, '烧烤味鱿鱼须呈深棕色，表面裹满烧烤调味料，视觉上须足完整，无断节。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的烧烤香料香混合着鱿鱼的鲜香，层次丰富。触感柔韧有嚼劲，不塞牙，入口先是鱿鱼的鲜甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡（三星，满五星），烧烤味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼须、烧烤调味料、食用盐、白砂糖，碳烤工艺，保质期8个月，是海鲜零食中风味浓郁的热门款。', 10, 5);
INSERT INTO `goods` VALUES (140, '泡椒味鱼皮', '/picture/57-1.jpg', '/picture/57-2.jpg', '/picture/57-3.jpg', 38.9, '泡椒味鱼皮呈淡黄色，点缀着泡椒的红色，视觉上色泽鲜亮，鱼皮完整。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上泡椒的酸辣香混合着鱼皮的鲜香，独特诱人。触感酥脆不粘牙，入口先是泡椒的酸辣，随即鱼皮的鲜香散开，味觉上酸辣适中（四星，满五星），鱼皮的酥脆与泡椒的酸爽融合，越嚼越香。主要原料：鱼皮、泡椒、食用盐、白醋，低温油炸（控油），保质期9个月，是海鲜零食中酸辣风味的小众款。', 10, 5);
INSERT INTO `goods` VALUES (141, '原味银鱼仔', '/picture/58-1.jpg', '/picture/58-2.jpg', '/picture/58-3.jpg', 42.9, '原味银鱼仔呈银白色，视觉上体型小巧均匀，无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的银鱼鲜香，混合着淡淡的海盐香，清新自然。触感柔韧有嚼劲，入口先是银鱼的鲜甜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工香精，保留银鱼的自然风味。主要原料：银鱼、食用盐、白砂糖，低温烘烤，保质期10个月，独立小包装，是海鲜零食中便携的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (142, '麻辣味花蛤肉', '/picture/59-1.jpg', '/picture/59-2.jpg', '/picture/59-3.jpg', 55.9, '麻辣味花蛤肉呈红棕色，表面裹满麻辣调味料，视觉上肉质饱满，无沙粒。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的麻辣香混合着花蛤的鲜香，香气扑鼻。触感肉质紧实有嚼劲，入口先是花蛤的鲜甜，随即麻辣味在舌尖散开，味觉上麻辣适中（五星，满五星），咸香入味，花蛤的鲜味与麻辣味融合恰到好处。主要原料：花蛤肉、辣椒面、花椒粉、食用盐，高温灭菌，保质期12个月，罐装密封，是海鲜零食中重口味的下酒菜。', 10, 5);
INSERT INTO `goods` VALUES (143, '芝士味鳕鱼粒', '/picture/60-1.jpg', '/picture/60-2.jpg', '/picture/60-3.jpg', 62.9, '芝士味鳕鱼粒呈奶白色，表面有芝士粉的均匀附着，视觉上颗粒饱满，质地细腻。咬下时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的芝士香混合着鳕鱼的鲜香，醇厚诱人。触感绵软有嚼劲，入口先是芝士的咸香，随即鳕鱼的鲜甜散开，味觉上咸甜平衡（二星，满五星），芝士味浓郁且不腻，鳕鱼的口感绵密。主要原料：鳕鱼肉、芝士粉、鸡蛋、食用盐，低温烘烤，保质期8个月，是海鲜零食中适合儿童的营养款。', 10, 5);
INSERT INTO `goods` VALUES (144, '盐焗味蛏子干', '/picture/62-1.jpg', '/picture/62-2.jpg', '/picture/62-3.jpg', 72.9, '盐焗味蛏子干呈淡黄色，视觉上肉质饱满，无沙无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上淡淡的海盐香混合着蛏子的鲜香，清新自然。触感肉质紧实有嚼劲，入口先是海盐的咸香，随即蛏子的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留蛏子的自然风味。主要原料：蛏子、食用海盐，低温盐焗，保质期12个月，是海鲜零食中高端的干货款。', 10, 5);
INSERT INTO `goods` VALUES (145, '蔓越莓软心饼干', '/picture/63-1.jpg', '/picture/63-2.jpg', '/picture/63-3.jpg', 18.9, '蔓越莓软心饼干外皮呈浅焦糖色，能看到暗红的蔓越莓果干嵌在其中，视觉上诱人十足。咬开时没有清脆声响，而是略带软糯的质感，嗅觉上蔓越莓的酸甜果香混合着黄油香气，清新不腻。触感外皮微酥，内芯软糯，入口先是黄油饼干的绵密，随即蔓越莓的酸甜在口腔中迸发，果干的嚼劲与饼干的软嫩融合，味觉上甜中带酸，层次丰富。主要原料：蔓越莓干、黄油、低筋面粉、糖粉，甜度：四星（满五星），保质期8个月，果干含量≥20%，是饼干系列中软心口感的代表，适合喜欢酸甜风味的人群。', 10, 1);
INSERT INTO `goods` VALUES (146, '阖家欢乐坚果礼盒', '/picture/64-1.jpg', '/picture/64-2.jpg', '/picture/64-3.jpg', 198.9, '阖家欢乐坚果礼盒外包装为中国红主色调，搭配金色祥云图案，视觉上喜庆大气，礼盒内包含巴旦木、夏威夷果、腰果、开心果、碧根果等8款坚果，独立罐装。开启礼盒时能听到礼盒盖的“啪”声，听觉上有仪式感，嗅觉上混合着各类坚果的醇香，浓郁不腻。触感礼盒质感厚实，坚果罐密封严实，每款坚果颗粒饱满酥脆，入口根据品类不同，或清甜或咸香，味觉上覆盖甜、咸、原味等多种风味，满足不同口味需求。所有坚果均采用低温烘焙工艺，无添加防腐剂，保质期12个月，是节日礼盒中经典的阖家分享款，适合春节、中秋等传统节日馈赠。', 10, 8);
INSERT INTO `goods` VALUES (147, '缤纷果干礼盒', '/picture/65-1.jpg', '/picture/65-2.jpg', '/picture/65-3.jpg', 168.9, '缤纷果干礼盒外包装为多彩渐变设计，视觉上活泼亮眼，礼盒内包含葡萄干、蔓越莓干、芒果干、草莓干、黄桃干等10款果干，独立小包装。开启时发出礼盒丝带的“嘶啦”声，听觉上有仪式感，嗅觉上混合着各类水果的香甜，清新自然。触感果干肉质饱满，软糯有嚼劲，入口根据品类不同，或酸甜或清甜，味觉上无添加人工香精，仅靠水果自然提味，甜度适中（二星至四星，满五星）。所有果干均采用冻干锁鲜工艺，保质期18个月，是节日礼盒中适合儿童与女性的清甜款。', 10, 8);
INSERT INTO `goods` VALUES (148, '年味肉食礼盒', '/picture/66-1.jpg', '/picture/66-2.jpg', '/picture/66-3.jpg', 258.9, '年味肉食礼盒外包装为复古国潮设计，视觉上年味十足，礼盒内包含酱牛肉、卤猪蹄、烤肠、熏鸡、香辣鸭脖等8款肉食，真空独立包装。开启时能听到真空包装的“啪”声，听觉上解压，嗅觉上混合着卤香、烤香等多种肉食香气，浓郁诱人。触感肉食肉质紧实，或酥烂或有嚼劲，入口根据品类不同，或咸香或麻辣，味觉上咸淡适中，风味浓郁且不腻。所有肉食均采用高温灭菌工艺，保质期9个月，是节日礼盒中适合家庭聚餐的硬菜款。', 10, 8);
INSERT INTO `goods` VALUES (149, '茶点饼干礼盒', '/picture/67-1.jpg', '/picture/67-2.jpg', '/picture/67-3.jpg', 158.9, '茶点饼干礼盒外包装为新中式设计，搭配水墨山水图案，视觉上雅致大气，礼盒内包含黄油曲奇、抹茶饼干、椰香薄脆、香葱苏打等10款饼干，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着黄油、奶香、茶香等多种香气，清新不腻。触感饼干或酥松或薄脆，入口根据品类不同，或香甜或咸香，味觉上甜度覆盖一星至四星（满五星），满足不同茶点需求。所有饼干均采用低温烘烤工艺，保质期10个月，是节日礼盒中适合品茶搭配的雅致款。', 10, 8);
INSERT INTO `goods` VALUES (150, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (151, '海鲜臻品礼盒', '/picture/69-1.jpg', '/picture/69-2.jpg', '/picture/69-3.jpg', 298.9, '海鲜臻品礼盒外包装为深海蓝主色调，视觉上高端大气，礼盒内包含烤虾、鱿鱼丝、鳗鱼丝、花蛤肉等8款海鲜零食，独立真空包装。开启时能听到真空包装的轻响，听觉上有质感，嗅觉上混合着海鲜的鲜香与烘烤香，清新无腥味。触感海鲜零食或柔韧或酥脆，入口根据品类不同，或鲜甜或麻辣，味觉上咸淡适中，保留海鲜的自然风味。所有海鲜均采用低温碳烤或高温灭菌工艺，保质期8-12个月不等，是节日礼盒中高端的海鲜特色款。', 10, 8);
INSERT INTO `goods` VALUES (152, '五谷杂粮礼盒', '/picture/70-1.jpg', '/picture/70-2.jpg', '/picture/70-3.jpg', 148.9, '五谷杂粮礼盒外包装为自然米色主色调，搭配谷物图案，视觉上健康质朴，礼盒内包含大米、小米、黑米、红豆、薏米等10款杂粮，独立密封罐装。开启时发出罐盖的“啪”声，听觉上解压，嗅觉上混合着各类谷物的清香，自然无异味。触感杂粮颗粒饱满，质地干燥，烹饪后口感或软糯或有嚼劲，入口根据品类不同，或清甜或清淡，味觉上无额外调味，保留谷物的自然风味。所有杂粮均无添加防腐剂，保质期18个月，是节日礼盒中适合馈赠长辈的健康款。', 10, 8);
INSERT INTO `goods` VALUES (153, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (154, '低糖健康礼盒', '/picture/73-1.jpg', '/picture/73-2.jpg', '/picture/73-3.jpg', 188.9, '低糖健康礼盒外包装为清新绿色主色调，视觉上健康自然，礼盒内包含无糖饼干、低糖坚果、无糖酸奶溶豆、杂粮脆片等10款低糖零食，独立包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着谷物香、奶香等清淡香气，无甜腻味。触感零食或酥松或酥脆，入口根据品类不同，或清淡或微甜，味觉上甜度均≤一星（满五星），无添加蔗糖。所有零食均采用健康工艺制作，保质期8-12个月不等，是节日礼盒中适合控糖人群的健康款。', 10, 8);
INSERT INTO `goods` VALUES (155, '环球零食礼盒', '/picture/74-1.jpg', '/picture/74-2.jpg', '/picture/74-3.jpg', 288.9, '环球零食礼盒外包装为多国风情设计，视觉上时尚大气，礼盒内包含进口饼干、巧克力、坚果、果干等12款全球特色零食，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各国零食的独特香气，层次丰富。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上覆盖不同国家的风味特色，甜度与咸度适中。所有零食均为正规进口，保质期6-12个月不等，是节日礼盒中适合年轻群体的时尚款。', 10, 8);
INSERT INTO `goods` VALUES (156, '进口黑金松露巧克力', '/picture/75-1.jpg', '/picture/75-2.jpg', '/picture/75-3.jpg', 198.9, '进口黑金松露巧克力呈深棕色的球形，表面裹有可可粉，视觉上哑光高级，单颗独立金箔包装。掰开时能听到巧克力脆皮的轻微脆响，听觉上柔和，嗅觉上浓郁的黑松露香气混合着可可的醇香，层次丰富且不腻。触感应指即融，内芯绵密丝滑，入口先是可可的微苦，随即黑松露的独特香气在口腔中散开，味觉上甜苦平衡（三星，满五星），可可含量≥70%，无添加代可可脂，回味悠长且有松露的独特回甘。主要原料：进口可可液块、黑松露粉、淡奶油，冷链运输保鲜，保质期6个月，是高端零食中巧克力控的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (157, '特级冻干榴莲干', '/picture/76-1.jpg', '/picture/76-2.jpg', '/picture/76-3.jpg', 168.9, '特级冻干榴莲干采用泰国金枕榴莲制作，呈淡黄色，视觉上果肉纹理清晰，无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的榴莲果香，纯正且无香精味。触感酥脆易嚼，入口即化，先是榴莲的香甜在舌尖散开，随即淡淡的奶香回味，味觉上甜而不腻（四星，满五星），冻干工艺保留90%以上榴莲营养，无添加蔗糖。主要原料：泰国金枕榴莲果肉，冻干锁鲜工艺，保质期12个月，独立密封包装，是高端零食中榴莲爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (158, '顶级鱼子酱薯片', '/picture/77-1.jpg', '/picture/77-2.jpg', '/picture/77-3.jpg', 228.9, '顶级鱼子酱薯片呈薄透的淡黄色，表面均匀附着鱼子酱与芝士粉，视觉上质感十足，单片独立包装。咬下时发出“啪”的清脆声响，听觉上解压，嗅觉上浓郁的鱼子酱咸香混合着芝士的奶香，醇厚诱人。触感薄脆易嚼，入口即化，先是鱼子酱的咸鲜在舌尖散开，随即芝士的醇香回味，味觉上咸甜平衡（二星，满五星），薯片采用非转基因马铃薯制作，无添加人工色素。主要原料：马铃薯片、鱼子酱、芝士粉、黄油，低温烘烤工艺，保质期8个月，是高端零食中轻奢的休闲款。', 10, 11);
INSERT INTO `goods` VALUES (159, '精选松茸坚果混合装', '/picture/78-1.jpg', '/picture/78-2.jpg', '/picture/78-3.jpg', 258.9, '精选松茸坚果混合装包含松茸碎、夏威夷果、碧根果、开心果等高端坚果，视觉上颗粒饱满，配色自然。混合时能听到坚果碰撞的轻微声响，听觉上解压，嗅觉上松茸的独特清香混合着坚果的醇香，层次独特。触感坚果酥脆，松茸碎绵软，入口先是坚果的醇香，随即松茸的清鲜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留食材自然风味。主要原料：精选松茸、进口坚果，低温烘焙工艺，保质期10个月，独立小包装，是高端零食中兼具营养与口感的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (160, '法式鹅肝酱饼干', '/picture/79-1.jpg', '/picture/79-2.jpg', '/picture/79-3.jpg', 188.9, '法式鹅肝酱饼干采用法式薄脆饼干搭配手工鹅肝酱，视觉上饼干金黄酥脆，鹅肝酱质地绵密。掰开饼干时发出“咔嚓”的脆响，听觉上清脆，嗅觉上鹅肝酱的浓郁醇香混合着饼干的黄油香，诱人食欲。触感饼干酥脆，鹅肝酱绵密，入口先是饼干的酥松，随即鹅肝酱的醇厚在口腔中散开，味觉上咸香适中（二星，满五星），无腥味，鹅肝酱含量≥40%。主要原料：法式薄脆饼干、新鲜鹅肝、黄油、食用盐，低温冷藏工艺，保质期6个月，是高端零食中法式风味的特色款。', 10, 11);
INSERT INTO `goods` VALUES (161, '冰岛即食海参', '/picture/80-1.jpg', '/picture/80-2.jpg', '/picture/80-3.jpg', 398.9, '冰岛即食海参呈深褐色，视觉上肉质厚实，参刺完整，独立真空包装。切开时能听到海参肉质的轻微“咯吱”声，听觉上有弹性，嗅觉上淡淡的海鲜咸香，无腥味。触感肉质Q弹有嚼劲，入口先是海参的鲜甜，随即淡淡的鲍汁提味（鲍汁款），味觉上咸淡适中（一星，满五星），无添加防腐剂，采用高温灭菌工艺锁鲜。主要原料：冰岛进口海参、鲍汁（可选），保质期12个月，开袋即食，是高端零食中滋补养生的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (162, '日式和牛脆片', '/picture/81-1.jpg', '/picture/81-2.jpg', '/picture/81-3.jpg', 268.9, '日式和牛脆片采用和牛雪花部位制作，呈浅棕色，视觉上纹理清晰，薄如蝉翼。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上和牛的醇香混合着日式照烧的甜香，浓郁不腻。触感薄脆易嚼，入口先是和牛的鲜香，随即照烧的甜咸在舌尖散开，味觉上甜咸平衡（三星，满五星），无添加人工香精，保留和牛的自然风味。主要原料：日式和牛、照烧酱、食用盐，低温烘烤工艺，保质期9个月，独立密封包装，是高端零食中肉食爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (163, '顶级白松露坚果酱', '/picture/82-1.jpg', '/picture/82-2.jpg', '/picture/82-3.jpg', 298.9, '顶级白松露坚果酱呈浅棕色，质地绵密，视觉上无颗粒感，玻璃罐装配金色瓶盖。搅拌时触感顺滑，听觉上无明显声响，嗅觉上白松露的独特清香混合着坚果的醇香，层次丰富。入口绵密顺滑，先是坚果的香甜在舌尖散开，随即白松露的清鲜回味，味觉上甜咸平衡（二星，满五星），可搭配面包、饼干食用，风味独特。主要原料：白松露粉、榛子仁、杏仁、黄油，低温熬煮工艺，保质期12个月，是高端零食中轻奢的佐餐款。', 10, 11);
INSERT INTO `goods` VALUES (164, '澳洲进口芒果干', '/picture/83-1.jpg', '/picture/83-2.jpg', '/picture/83-3.jpg', 158.9, '澳洲进口芒果干采用澳洲凯特芒制作，呈金黄色，视觉上果肉厚实，纹理清晰，无添加色素。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的芒果果香，纯正且无香精味。触感肉质饱满，软糯有嚼劲，不粘牙，入口先是芒果的清甜，随即淡淡的果酸提味，味觉上甜酸平衡（三星，满五星），无添加蔗糖，仅靠芒果自然提甜。主要原料：澳洲凯特芒果肉，冻干锁鲜工艺，保质期18个月，独立密封包装，是高端零食中果干类的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (165, '奢享鱼子酱巧克力', '/picture/84-1.jpg', '/picture/84-2.jpg', '/picture/84-3.jpg', 288.9, '奢享鱼子酱巧克力呈球形，外层为黑巧克力，内芯包裹鱼子酱夹心，视觉上黑金配色，高级感十足。咬开时能听到巧克力脆皮的脆响，听觉上满足，嗅觉上黑巧克力的微苦混合着鱼子酱的咸鲜，层次独特。触感外层酥脆，内芯绵密，入口先是黑巧克力的醇厚，随即鱼子酱的咸鲜在口腔中散开，味觉上甜咸平衡（二星，满五星），可可含量≥80%，鱼子酱为进口顶级款。主要原料：进口黑巧克力、顶级鱼子酱、淡奶油，冷链保鲜，保质期6个月，是高端零食中极具特色的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (166, '草莓味磨牙棒', '/picture/35-1.jpg', '/picture/35-2.jpg', '/picture/35-3.jpg', 18.9, '草莓味磨牙棒呈长条状，视觉上淡粉色（天然草莓粉调色），表面有细密的纹理，适合儿童抓握磨牙。咬嚼时发出轻微的“咯吱”声，听觉上温和，嗅觉上淡淡的草莓果香混合着小麦的清香，清新不腻。触感坚硬但不硌牙，专为出牙期宝宝设计，能缓解牙龈不适，入口先是草莓的清甜，随即小麦的醇香散开，味觉上甜度极低（一星，满五星），无添加香精色素。主要原料：小麦粉、草莓粉、奶粉、橄榄油，保质期12个月，独立包装，干净卫生，是儿童零食中针对性的磨牙款。', 10, 3);
INSERT INTO `goods` VALUES (167, '咖啡伴侣礼盒', '/picture/71-1.jpg', '/picture/71-2.jpg', '/picture/71-3.jpg', 178.9, '咖啡伴侣礼盒外包装为简约轻奢设计，视觉上高级感十足，礼盒内包含各类口味曲奇、焦糖饼干、坚果仁、巧克力等8款搭配咖啡的零食，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着咖啡香（附赠挂耳咖啡）、奶香、焦糖香等，浓郁不腻。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上甜度覆盖二星至四星（满五星），与咖啡搭配口感互补。所有零食均采用低温工艺制作，保质期9-12个月不等，是节日礼盒中适合咖啡爱好者的轻奢款。', 10, 8);
INSERT INTO `goods` VALUES (168, '香蕉味泡芙球', '/picture/36-1.jpg', '/picture/36-2.jpg', '/picture/36-3.jpg', 22.9, '香蕉味泡芙球呈淡黄色的中空球状，视觉上小巧可爱，表面有细密的气孔，适合儿童抓食。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的香蕉果香混合着奶香，清新自然。触感空心酥脆，入口即化，先是香蕉的清甜在舌尖散开，随即奶香回味，味觉上甜度适中（二星，满五星），无添加人工香精。主要原料：香蕉泥、奶粉、小麦粉、植物油，保质期8个月，非油炸工艺，是儿童零食中口感轻盈的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (169, '精选羊肚菌脆片', '/picture/85-1.jpg', '/picture/85-2.jpg', '/picture/85-3.jpg', 218.9, '精选羊肚菌脆片采用云南特级羊肚菌制作，呈深褐色，视觉上菌纹清晰，完整无碎。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上羊肚菌的独特清香混合着淡淡的海盐香，清新自然。触感酥脆易嚼，入口先是羊肚菌的清鲜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工调味，冻干工艺保留羊肚菌营养。主要原料：云南特级羊肚菌、食用海盐，冻干工艺，保质期10个月，独立包装，是高端零食中兼具营养与口感的特色款。', 10, 11);
INSERT INTO `goods` VALUES (170, '蓝莓味果泥', '/picture/37-1.jpg', '/picture/37-2.jpg', '/picture/37-3.jpg', 21.9, '蓝莓味果泥呈深紫色的泥状，视觉上质地细腻无颗粒，包装为便携吸嘴袋，方便儿童食用。挤压时触感顺滑，听觉上无明显声响，嗅觉上浓郁的蓝莓果香，清新不刺鼻，无香精味。入口绵密顺滑，无需咀嚼，先是蓝莓的酸甜在舌尖散开，随即水果的自然清甜回味，味觉上无添加蔗糖（一星，满五星），仅靠蓝莓自然提甜。主要原料：蓝莓果肉（≥90%）、苹果泥、维生素C，保质期12个月，无防腐剂，是儿童零食中补充花青素的营养款。', 10, 3);
INSERT INTO `goods` VALUES (171, '五香开口松子', '/picture/46-1.jpg', '/picture/46-2.jpg', '/picture/46-3.jpg', 69.9, '五香开口松子外壳呈棕红色，开口均匀，视觉上颗粒饱满修长，果仁呈淡黄色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上浓郁的五香料香混合着松子的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是五香的咸香，随即松子的清甜散开，味觉上咸淡适中（二星，满五星），五香味浓郁且不掩盖松子本身的香气，越嚼越有回甘。主要原料：松子、五香粉、食用盐，低温烘焙，保质期8个月，无添加香精，是坚果系列中咸香风味的特色款。', 10, 4);
INSERT INTO `goods` VALUES (172, '孜然味烤鱿鱼板', '/picture/61-1.jpg', '/picture/61-2.jpg', '/picture/61-3.jpg', 47.9, '孜然味烤鱿鱼板呈深棕色，表面有孜然颗粒的均匀分布，视觉上板状完整，厚度均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上孜然的辛香混合着鱿鱼的鲜香，独特诱人。触感柔韧有嚼劲，入口先是鱿鱼的鲜甜，随即孜然的咸香在舌尖散开，味觉上咸淡适中（二星，满五星），孜然味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼板、孜然粉、食用盐、白砂糖，碳烤工艺，保质期9个月，是海鲜零食中孜然风味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (173, '芝士咸味饼干', '/picture/1768183025317.jpg', '/picture/1768183025334.jpg', '/picture/1768183025348.jpg', 19.9, '芝士咸味饼干呈淡黄色，表面有芝士粉的均匀附着，视觉上质感十足。轻咬时发出清脆的脆响，嗅觉上浓郁的芝士咸香混合着黄油香气，诱人食欲。触感酥脆不粘牙，入口先是芝士的咸香醇厚，随即黄油的绵密感在舌尖散开，味觉上咸度适中，还带着芝士特有的微酸回甘，层次丰富。主要原料：芝士粉、黄油、小麦粉、食用盐，甜度：一星（满五星），保质期10个月，芝士含量≥15%，是饼干系列中咸味芝士控的必选款。', 10, 1);
INSERT INTO `goods` VALUES (174, '番茄味薯片脆', '/picture/1768183053016.jpg', '/picture/1768183053030.jpg', '/picture/1768183053075.jpg', 7.9, '番茄味薯片脆呈薄透的橙红色，表面裹满番茄粉，视觉上色彩鲜亮。咬下时发出清脆的“啪”声，听觉上解压十足，嗅觉上浓郁的番茄酸甜果香混合着土豆香，清新不腻。触感薄脆易嚼，入口即化，先是番茄的酸甜在舌尖迸发，随即土豆的醇香回味，味觉上酸甜平衡，番茄味浓郁且不齁甜。主要原料：马铃薯片、番茄粉、白砂糖、食用盐，保质期10个月，薄切烘烤工艺，低脂低油，是膨化系列中经典的番茄风味款。', 11, 2);
INSERT INTO `goods` VALUES (175, '原味鲜虾片', '/picture/1768183083877.jpg', '/picture/1768183083891.jpg', '/picture/11-3.jpg', 23.9, '原味鲜虾片呈薄透的淡粉色，视觉上轻盈通透，能看到细微的虾粉颗粒。咬下时发出清脆的“啪”声，听觉上解压有趣，嗅觉上浓郁的鲜虾鲜香，清新无腥味。触感薄脆易嚼，入口即化，先是鲜虾的鲜甜在舌尖散开，随即淡淡的盐味提味，味觉上咸淡适中（一星，满五星），无添加人工香精。主要原料：虾粉（≥40%）、小麦粉、食用盐、植物油，保质期9个月，非油炸烘烤，是儿童零食中补充优质蛋白的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (176, '柠檬味烤鱼片', '/picture/1768183098288.jpg', '/picture/12-2.jpg', '/picture/12-3.jpg', 44.9, '柠檬味烤鱼片呈淡黄色，视觉上质地轻薄，纹理清晰。咬下时发出轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上柠檬的清香混合着鱼肉的鲜香，清新不腻。触感柔韧有嚼劲，入口先是柠檬的酸甜，随即鱼肉的鲜甜散开，味觉上酸甜平衡（二星，满五星），柠檬味掩盖了鱼肉的腥味，口感更清新。主要原料：马面鱼、柠檬汁、食用盐、白砂糖，低温烘烤，保质期10个月，是海鲜零食中清新风味的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (177, '抹茶红豆夹心饼干', '/picture/1768183115678.jpg', '/picture/13-2.jpg', '/picture/13-3.jpg', 16.9, '抹茶红豆夹心饼干外层是淡绿色的抹茶饼干体，中间夹着暗红色的红豆沙夹心，视觉上配色清新雅致。掰开时能听到饼干体轻微的脆响，夹心则软糯拉丝，嗅觉上宇治抹茶的清苦香气混合着红豆的甜香，淡雅宜人。触感外层酥脆，夹心绵密，入口先是抹茶的清苦，随即红豆夹心的香甜中和苦味，味觉上甜苦平衡，还带着抹茶特有的茶韵回甘。主要原料：宇治抹茶粉、红豆沙、小麦粉、黄油，甜度：三星（满五星），保质期9个月，无人工色素，是饼干系列中兼具日式风味的特色款。', 10, 1);
INSERT INTO `goods` VALUES (178, '海盐焦糖饼干', '/picture/1768183141942.jpg', '/picture/14-2.jpg', '/picture/14-3.jpg', 14.9, '海盐焦糖饼干呈焦糖色，表面有细密的盐粒点缀，视觉上光泽诱人。轻咬时发出清脆的“咔嚓”声，嗅觉上浓郁的焦糖香气混合着淡淡的海盐气息，甜咸交织。触感酥脆易断，入口先是焦糖的焦香甜味，随即海盐的咸香在舌尖散开，中和甜腻，味觉上回味有淡淡的黄油香，层次丰富。主要原料：焦糖酱、食用海盐、小麦粉、黄油，甜度：四星（满五星），保质期10个月，采用低温烘烤工艺，是饼干系列中甜咸风味的热门款。', 10, 1);
INSERT INTO `goods` VALUES (179, '花生酱夹心饼干', '/picture/15-1.jpg', '/picture/15-2.jpg', '/picture/15-3.jpg', 13.9, '花生酱夹心饼干外层是金黄色的酥性饼干，中间夹着醇厚的花生酱夹心，视觉上饱满厚实。掰开时能听到饼干的脆响，同时花生酱夹心会微微拉丝，嗅觉上浓郁的花生烘烤香气扑面而来，醇厚不腻。触感外层酥脆，夹心绵密，入口先是饼干的酥松，随即花生酱的咸香与微甜在口腔中散开，味觉上花生味浓郁，还带着一丝烘烤的焦香。主要原料：花生酱、小麦粉、黄油、白砂糖，甜度：三星（满五星），保质期9个月，花生酱含量≥30%，是饼干系列中经典的咸甜夹心款。', 10, 1);
INSERT INTO `goods` VALUES (180, '椰香薄脆饼干', '/picture/16-1.jpg', '/picture/16-2.jpg', '/picture/16-3.jpg', 11.9, '椰香薄脆饼干呈薄透的奶白色，能看到细密的椰蓉颗粒，视觉上轻盈通透。咬下时发出清脆的“咔嚓”声，嗅觉上浓郁的椰香混合着小麦的清香，清新自然。触感薄脆易嚼，入口即化，先是椰蓉的香甜在舌尖散开，随即小麦的醇香回味，味觉上甜而不腻，椰香浓郁且持久。主要原料：椰蓉、小麦粉、黄油、椰奶，甜度：二星（满五星），保质期11个月，采用薄切烘烤工艺，是饼干系列中口感轻盈的休闲款。', 10, 1);
INSERT INTO `goods` VALUES (181, '紫薯燕麦饼干', '/picture/17-1.jpg', '/picture/17-2.jpg', '/picture/17-3.jpg', 17.9, '紫薯燕麦饼干呈淡紫色，嵌有燕麦片的颗粒，视觉上健康自然。掰开时能听到燕麦片与饼干体碰撞的轻微声响，嗅觉上紫薯的香甜混合着燕麦的谷物香气，清淡不腻。触感酥松中带着燕麦的嚼劲，入口先是紫薯的清甜，随即燕麦的谷物香在口腔中散开，味觉上低糖低脂，口感丰富，还带着一丝谷物的回甘。主要原料：紫薯泥、燕麦片、小麦粉、橄榄油，甜度：一星（满五星），保质期8个月，无添加蔗糖，是饼干系列中健康代餐的优选款。', 10, 1);
INSERT INTO `goods` VALUES (182, '黄油奶香曲奇饼干', '/picture/18-1.jpg', '/picture/18-2.jpg', '/picture/18-3.jpg', 12.9, '这款黄油奶香曲奇饼干呈诱人的金黄色，表面分布着细密的黄油颗粒，视觉上层次分明。掰开时能听到清脆的“咔嚓”声，瞬间释放出浓郁的黄油与奶香交织的醇厚香气，嗅觉上让人垂涎欲滴。触感应指即碎，酥松不粘牙，入口先是黄油的绵密醇厚，紧接着是淡淡奶香在舌尖散开，甜而不腻，尾调还带着一丝天然的香草气息，味觉体验丰富。主要原料选用新西兰黄油、高筋小麦粉、进口奶粉，甜度：三星（满五星），保质期长达12个月，独立小包装设计，无论是下午茶搭配咖啡，还是日常解馋都十分合适，是饼干系列中经典的奶香风味代表作。', 10, 1);
INSERT INTO `goods` VALUES (183, '红豆薏米饼干', '/picture/19-1.jpg', '/picture/19-2.jpg', '/picture/19-3.jpg', 15.9, '红豆薏米饼干呈浅棕色，能看到红豆与薏米的颗粒，视觉上健康质朴。掰开时发出轻微的酥响，嗅觉上红豆的香甜混合着薏米的谷物清香，淡雅宜人。触感酥松易嚼，入口先是谷物的醇香，随即红豆的清甜散开，味觉上低糖清淡，还带着薏米的微甘，饱腹感强。主要原料：红豆粉、薏米粉、小麦粉、植物油，甜度：一星（满五星），保质期9个月，无添加防腐剂，是饼干系列中主打健康养生的特色款。', 10, 1);
INSERT INTO `goods` VALUES (184, '原味空心薯笛', '/picture/20-1.jpg', '/picture/20-2.jpg', '/picture/20-3.jpg', 8.9, '原味空心薯笛呈金黄的中空管状，表面有细密的纹理，视觉上酥脆诱人。咬下时发出“咔嚓”的清脆声响，听觉上极具解压感，嗅觉上浓郁的土豆原香扑面而来，清新自然。触感空心酥脆，轻捏即碎，入口先是土豆的醇香，随即淡淡的盐味提味，味觉上咸淡适中，薯香浓郁且不油腻，越嚼越有谷物的回甘。主要原料：马铃薯粉、玉米淀粉、食用盐、棕榈油，保质期9个月，采用非油炸膨化工艺，低脂轻卡，是膨化系列中经典的原味休闲款，适合全家共享。', 10, 2);
INSERT INTO `goods` VALUES (185, '烧烤味玉米浪', '/picture/21-1.jpg', '/picture/21-2.jpg', '/picture/21-3.jpg', 9.9, '烧烤味玉米浪呈波浪形的金黄色，表面均匀附着烧烤调味料，视觉上色泽诱人。咬开时发出“咔嚓”的脆响，听觉上清脆悦耳，嗅觉上浓郁的烧烤香料香混合着玉米的清甜，层次丰富。触感波浪形的酥脆质感，入口先是玉米的香甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡，还带着一丝烟熏的香气，回味悠长。主要原料：玉米粉、烧烤调味料、植物油、白砂糖，保质期8个月，非油炸工艺，是膨化系列中风味浓郁的热门款。', 10, 2);
INSERT INTO `goods` VALUES (186, '黑巧克力榛子饼干', '/picture/22-1.jpg', '/picture/22-2.jpg', '/picture/22-3.jpg', 15.9, '黑巧克力榛子饼干通体呈深棕色调，嵌有饱满的榛子碎，视觉上极具质感。轻咬时能听到巧克力脆皮与饼干酥层碰撞的脆响，嗅觉上立刻捕捉到微苦的黑巧克力香与烘烤榛子的坚果香气，层次丰富。触感酥脆中带着榛子的微硬颗粒感，入口先是黑巧克力的微苦醇厚，随即榛子的香脆与饼干的酥松融合，甜苦平衡，味觉上回味悠长。主要原料：可可含量70%的黑巧克力、榛子仁、低筋面粉、黄油，甜度：二星（满五星），保质期10个月，不含反式脂肪酸，是饼干系列中兼具巧克力风味与坚果口感的特色款。', 10, 1);
INSERT INTO `goods` VALUES (187, '海苔味米饼', '/picture/23-1.jpg', '/picture/23-2.jpg', '/picture/23-3.jpg', 10.9, '海苔味米饼呈米白色，表面有海苔碎的均匀分布，视觉上清新素雅。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上海苔的鲜咸香气混合着大米的清香，淡雅宜人。触感酥脆中带着大米的蓬松感，入口先是大米的醇香，随即海苔的鲜咸散开，味觉上咸淡适中，还带着一丝米香的回甘，口感轻盈不腻。主要原料：大米粉、海苔碎、食用盐、植物油，保质期12个月，非油炸膨化，是膨化系列中适合儿童的清淡款。', 10, 2);
INSERT INTO `goods` VALUES (188, '香辣味虾条', '/picture/24-1.jpg', '/picture/24-2.jpg', '/picture/24-3.jpg', 11.9, '香辣味虾条呈橙红色的长条状，表面裹满香辣调味料，视觉上色泽诱人。咬下时发出“咔嚓”的脆响，听觉上极具满足感，嗅觉上浓郁的虾香混合着辣椒的辛香，香气扑鼻。触感酥脆不粘牙，入口先是鲜虾的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中，咸香入味，虾味浓郁且持久。主要原料：虾粉、小麦粉、辣椒面、植物油，保质期8个月，虾粉含量≥15%，是膨化系列中重口味爱好者的优选款。', 10, 2);
INSERT INTO `goods` VALUES (189, '芝士味空心脆', '/picture/25-1.jpg', '/picture/25-2.jpg', '/picture/25-3.jpg', 13.9, '芝士味空心脆呈淡黄色的中空球状，表面有芝士粉的附着，视觉上呆萌可爱。咬开时发出“嘭”的轻响，听觉上解压有趣，嗅觉上浓郁的芝士咸香混合着奶香，醇厚诱人。触感空心酥脆，入口即碎，先是芝士的咸香在口腔中散开，随即奶香回味，味觉上咸甜平衡，芝士味浓郁且不腻。主要原料：芝士粉、小麦粉、黄油、食用盐，保质期9个月，非油炸工艺，是膨化系列中芝士控的必选款。', 10, 2);
INSERT INTO `goods` VALUES (190, '芥末味青豆脆', '/picture/26-1.jpg', '/picture/26-2.jpg', '/picture/26-3.jpg', 12.9, '芥末味青豆脆呈翠绿色，包裹着淡淡的芥末调味粉，视觉上清新亮眼。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上芥末的微辛香气混合着青豆的清香，层次独特。触感酥脆中带着青豆的颗粒感，入口先是青豆的清甜，随即芥末的微辛在舌尖散开，味觉上辛而不辣，咸香入味，越嚼越有青豆的回甘。主要原料：青豆、芥末粉、食用盐、植物油，保质期10个月，低温膨化工艺，是膨化系列中风味独特的小众款。', 10, 2);
INSERT INTO `goods` VALUES (191, '蜂蜜黄油味薯条', '/picture/27-1.jpg', '/picture/27-2.jpg', '/picture/27-3.jpg', 14.9, '蜂蜜黄油味薯条呈金黄的长条状，表面裹满蜂蜜黄油酱，视觉上光泽诱人。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的黄油香混合着蜂蜜的甜香，甜而不腻。触感酥脆中带着微微的绵密感，入口先是黄油的醇厚，随即蜂蜜的清甜散开，味觉上甜咸平衡，黄油味浓郁且回味有奶香。主要原料：马铃薯条、黄油、蜂蜜、食用盐，保质期8个月，非油炸烘烤，是膨化系列中甜咸风味的热门款。', 10, 2);
INSERT INTO `goods` VALUES (192, '藤椒味洋芋片', '/picture/28-1.jpg', '/picture/28-2.jpg', '/picture/28-3.jpg', 10.9, '藤椒味洋芋片呈薄透的淡黄色，表面有藤椒粉的均匀附着，视觉上清爽质朴。咬下时发出“啪”的清脆声响，听觉上解压有趣，嗅觉上藤椒的麻香混合着土豆的清香，独特诱人。触感薄脆易嚼，入口先是土豆的醇香，随即藤椒的麻香在舌尖散开，味觉上麻而不苦，咸香入味，还带着一丝藤椒的清鲜。主要原料：马铃薯片、藤椒粉、食用盐、植物油，保质期9个月，薄切工艺，是膨化系列中川味特色的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (193, '肉松味米卷', '/picture/29-1.jpg', '/picture/29-2.jpg', '/picture/29-3.jpg', 15.9, '肉松味米卷呈米白色的卷状，表面裹满肉松碎，视觉上饱满诱人。咬开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上肉松的咸香混合着大米的清香，浓郁不腻。触感外层酥脆，内芯蓬松，入口先是肉松的咸香，随即大米的醇香散开，味觉上咸甜适中，肉松味浓郁且有嚼劲。主要原料：大米粉、肉松、白砂糖、食用盐，保质期12个月，非油炸膨化，是膨化系列中饱腹感强的代餐款。', 10, 2);
INSERT INTO `goods` VALUES (194, '海盐味豌豆脆', '/picture/30-1.jpg', '/picture/30-2.jpg', '/picture/30-3.jpg', 11.9, '海盐味豌豆脆呈淡绿色，表面有细密的海盐颗粒，视觉上清新自然。咬下时发出“咔嚓”的脆响，听觉上解压十足，嗅觉上豌豆的清香混合着海盐的咸香，清淡不腻。触感酥脆易嚼，入口先是豌豆的清甜，随即海盐的咸香提味，味觉上咸淡适中，豌豆味浓郁且回甘持久。主要原料：豌豆粉、食用海盐、植物油、玉米淀粉，保质期10个月，非油炸工艺，是膨化系列中健康轻卡的休闲款。', 10, 2);
INSERT INTO `goods` VALUES (195, '香葱咸味苏打饼干', '/picture/31-1.jpg', '/picture/31-2.jpg', '/picture/31-3.jpg', 9.8, '香葱咸味苏打饼干呈奶白色基底，点缀着翠绿的香葱碎，视觉上清新自然。掰开时发出“啪”的清脆声响，嗅觉上浓郁的香葱香气混合着小麦的清香扑面而来，咸香不刺鼻。触感干爽不粘手，酥松易嚼，入口先是淡淡的小麦香，紧接着香葱的鲜咸在舌尖散开，口感清爽不腻，味觉上咸度适中，还带着苏打饼干特有的微碱性回甘。主要原料：小麦粉、香葱、食用纯碱、食用盐，甜度：一星（满五星），保质期9个月，无额外添加蔗糖，适合控糖人群，是饼干系列中经典的咸味休闲款。', 10, 1);
INSERT INTO `goods` VALUES (196, '水果味星星软糖', '/picture/32-1.jpg', '/picture/32-2.jpg', '/picture/32-3.jpg', 19.9, '水果味星星软糖呈五彩的星星造型，视觉上色彩鲜艳（采用天然果蔬色素），颗颗饱满晶莹，萌趣十足。捏动时触感Q弹软糯，无硬芯，听觉上无明显声响，嗅觉上浓郁的草莓、橙子、葡萄等混合水果果香，清新不刺鼻。入口软糯有嚼劲，不粘牙，先是草莓的酸甜在舌尖散开，随即橙子的清香、葡萄的清甜依次迸发，味觉上甜度适中（二星，满五星），无添加人工香精与防腐剂。主要原料：麦芽糖浆、天然果蔬汁、明胶、维生素C，保质期18个月，每颗独立包装，干净卫生，是儿童零食中补充维生素的趣味款。', 10, 3);
INSERT INTO `goods` VALUES (197, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (198, '原味溶豆（酸奶味）', '/picture/34-1.jpg', '/picture/34-2.jpg', '/picture/34-3.jpg', 29.9, '酸奶味溶豆呈迷你的小颗粒状，视觉上奶白色，蓬松轻盈，造型小巧适合儿童抓握。轻捏即碎，触感绵软，听觉上无明显声响，嗅觉上浓郁的酸奶奶香，清新自然。入口即溶，无需咀嚼，先是酸奶的酸甜在舌尖化开，随即奶香回味，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠酸奶自然提味。主要原料：酸奶、奶粉、玉米淀粉、益生菌，保质期6个月，冻干工艺锁鲜，是儿童零食中适合低龄宝宝的辅食款。', 10, 3);
INSERT INTO `goods` VALUES (199, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (200, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (201, '奶香动物造型饼干', '/picture/33-1.jpg', '/picture/33-2.jpg', '/picture/33-3.jpg', 16.9, '这款奶香动物造型饼干采用可爱的小熊、小兔、小猫等动物模具制作，视觉上色彩柔和（无人工色素），造型萌趣十足，能瞬间吸引儿童注意力。掰开时发出轻微的“咔嚓”声，听觉上温和不刺耳，嗅觉上浓郁的奶香混合着小麦的清香，清新自然无异味。触感酥松易嚼，专为儿童咀嚼能力设计，不粘牙且不易噎食，入口先是奶香的绵密，随即小麦的醇香在舌尖散开，味觉上甜度极低（一星，满五星），无添加蔗糖，仅靠奶粉自然提甜，安全健康。主要原料：高筋小麦粉、全脂奶粉、鸡蛋、橄榄油，保质期12个月，独立小包装方便携带，是儿童零食中兼具趣味性与安全性的经典款。', 10, 3);
INSERT INTO `goods` VALUES (202, '芝士味小馒头', '/picture/38-1.jpg', '/picture/38-2.jpg', '/picture/38-3.jpg', 17.9, '芝士味小馒头呈迷你的奶黄色球状，视觉上小巧圆润，适合儿童抓握食用。咬下时发出轻微的“咔嚓”声，听觉上温和，嗅觉上浓郁的芝士香混合着奶香，醇厚不腻。触感酥松易嚼，入口即化，先是芝士的咸香在舌尖散开，随即奶香回味，味觉上咸甜适中（二星，满五星），无添加人工色素。主要原料：奶粉、芝士粉、小麦粉、鸡蛋，保质期10个月，独立小包装，是儿童零食中经典的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (203, '芒果味QQ糖', '/picture/39-1.jpg', '/picture/39-2.jpg', '/picture/39-3.jpg', 15.9, '芒果味QQ糖呈芒果形状的半透明状，视觉上金黄诱人，造型逼真可爱。捏动时触感Q弹有弹性，听觉上无明显声响，嗅觉上浓郁的芒果果香，清新自然无异味。入口软糯有嚼劲，不粘牙，先是芒果的清甜在舌尖散开，随即淡淡的果酸提味，味觉上甜度适中（三星，满五星），采用天然芒果汁调色调味。主要原料：麦芽糖浆、芒果汁、明胶、柠檬酸，保质期18个月，独立包装，是儿童零食中趣味十足的糖果款。', 10, 3);
INSERT INTO `goods` VALUES (204, '鳕鱼肠（芝士味）', '/picture/40-1.jpg', '/picture/40-2.jpg', '/picture/40-3.jpg', 25.9, '芝士味鳕鱼肠呈奶白色的长条状，视觉上质地均匀，无杂质，包装上印有卡通图案，吸引儿童。咬开时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的鳕鱼鲜香混合着芝士的咸香，醇厚不腻。触感弹嫩有嚼劲，专为儿童设计的软嫩口感，入口先是鳕鱼的鲜甜，随即芝士的咸香在口腔中散开，味觉上咸淡适中，无腥味，芝士味浓郁且自然。主要原料：鳕鱼肉（≥60%）、芝士粉、鸡蛋、食用盐，保质期9个月，独立真空包装，开袋即食，是儿童零食中补充优质蛋白的营养款。', 10, 3);
INSERT INTO `goods` VALUES (205, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (206, '原味手剥巴旦木', '/picture/42-1.jpg', '/picture/42-2.jpg', '/picture/42-3.jpg', 39.9, '原味手剥巴旦木外壳呈浅棕色，带有自然的纹理，视觉上饱满厚实，果仁呈奶白色，颗粒均匀。剥开外壳时能听到轻微的“咔嚓”声，听觉上解压，嗅觉上浓郁的巴旦木坚果原香，清淡不腻。触外壳坚硬但易剥，果仁触感饱满酥脆，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无额外调味（一星，满五星），仅靠巴旦木自然的咸香，越嚼越香，回甘持久。主要原料：精选巴旦木，无添加任何调味料，保质期12个月，低温烘焙锁鲜，是坚果系列中保留原味的经典款，富含优质脂肪与维生素E。', 10, 4);
INSERT INTO `goods` VALUES (207, '盐焗夏威夷果', '/picture/43-1.jpg', '/picture/43-2.jpg', '/picture/43-3.jpg', 59.9, '盐焗夏威夷果外壳呈棕褐色，带有天然的纹理，配有开果器，视觉上颗粒饱满圆润。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的坚果香混合着淡淡的海盐气息，咸香诱人。触感果仁绵密酥脆，入口先是海盐的咸香提味，随即夏威夷果特有的奶香在口腔中散开，味觉上咸甜平衡（二星，满五星），口感绵密且不腻，越嚼越有奶香回甘。主要原料：夏威夷果、食用海盐，低温烘焙，保质期10个月，无添加防腐剂，是坚果系列中口感绵密的高端款。', 10, 4);
INSERT INTO `goods` VALUES (208, '炭烧腰果', '/picture/44-1.jpg', '/picture/44-2.jpg', '/picture/44-3.jpg', 45.9, '炭烧腰果呈焦糖色，表面有细密的炭烧纹理，视觉上色泽诱人，颗粒饱满无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的炭烧香混合着腰果的坚果香，层次丰富。触感酥脆不粘牙，入口先是炭烧的焦香，随即腰果的清甜散开，味觉上咸甜适中（三星，满五星），炭烧味浓郁且不糊，回味有坚果的醇香。主要原料：腰果、白砂糖、食用盐、植物油，低温炭烧工艺，保质期11个月，是坚果系列中风味独特的热门款。', 10, 4);
INSERT INTO `goods` VALUES (209, '蜂蜜琥珀核桃仁', '/picture/45-1.jpg', '/picture/45-2.jpg', '/picture/45-3.jpg', 38.9, '蜂蜜琥珀核桃仁呈透亮的焦糖色，包裹着一层薄蜜，视觉上光泽诱人，核桃仁完整无碎。咬下时发出“咔嚓”的脆响，听觉上满足感十足，嗅觉上浓郁的蜂蜜甜香混合着核桃的坚果香，甜而不腻。触感酥脆中带着微微的粘糯，入口先是蜂蜜的清甜，随即核桃的醇香在舌尖散开，味觉上甜咸平衡（四星，满五星），蜂蜜味浓郁且不齁甜，核桃的苦涩感被中和得恰到好处。主要原料：核桃仁、蜂蜜、白砂糖、白芝麻，低温熬煮挂浆，保质期9个月，是坚果系列中甜口的经典款。', 10, 4);
INSERT INTO `goods` VALUES (210, '原味碧根果', '/picture/47-1.jpg', '/picture/47-2.jpg', '/picture/47-3.jpg', 55.9, '原味碧根果外壳呈浅棕色，带有自然的裂纹，视觉上果仁饱满，易剥取。撬开外壳时发出“啪”的轻响，听觉上满足，嗅觉上浓郁的碧根果坚果香，清淡不腻，无额外调味。触感果仁酥脆绵密，入口先是坚果的醇香，随即淡淡的油脂香在舌尖散开，味觉上无添加（一星，满五星），仅靠碧根果自然的咸香，口感绵密且回味悠长。主要原料：精选碧根果，低温烘焙，保质期12个月，是坚果系列中保留原味的高端款，富含不饱和脂肪酸。', 10, 4);
INSERT INTO `goods` VALUES (211, '香辣花生', '/picture/48-1.jpg', '/picture/48-2.jpg', '/picture/48-3.jpg', 19.9, '香辣花生呈红棕色，表面裹满香辣调味料，视觉上色泽鲜亮，颗粒饱满无瘪粒。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的辣椒香混合着花生的烘烤香，香气扑鼻。触感酥脆不粘牙，入口先是花生的香甜，随即香辣味在舌尖散开，味觉上辣度适中（三星，满五星），咸香入味，花生的醇香与辣椒的辛香融合恰到好处。主要原料：花生、辣椒面、花椒粉、食用盐，低温烘烤，保质期10个月，是坚果系列中重口味的平价款。', 10, 4);
INSERT INTO `goods` VALUES (212, '抹茶味杏仁', '/picture/49-1.jpg', '/picture/49-2.jpg', '/picture/49-3.jpg', 42.9, '抹茶味杏仁呈淡绿色，表面均匀附着抹茶粉，视觉上清新雅致，杏仁颗粒完整。咬下时发出“咔嚓”的脆响，听觉上清脆，嗅觉上宇治抹茶的清苦香气混合着杏仁的坚果香，层次独特。触感酥脆易嚼，入口先是抹茶的清苦，随即杏仁的清甜散开，味觉上甜苦平衡（二星，满五星），抹茶味浓郁且不涩，杏仁的醇香回味持久。主要原料：杏仁、宇治抹茶粉、白砂糖、植物油，低温烘焙，保质期9个月，是坚果系列中风味新颖的特色款。', 10, 4);
INSERT INTO `goods` VALUES (213, '盐焗开心果', '/picture/50-1.jpg', '/picture/50-2.jpg', '/picture/50-3.jpg', 68.9, '盐焗开心果外壳呈淡绿色，开口率≥95%，视觉上颗粒饱满，果仁呈翠绿色。剥开外壳时发出轻微的“咯吱”声，听觉上解压，嗅觉上淡淡的海盐香混合着开心果的坚果香，清新自然。触感果仁酥脆有嚼劲，入口先是海盐的咸香提味，随即开心果的清甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留开心果的自然风味。主要原料：开心果、食用海盐，低温烘焙，保质期11个月，是坚果系列中健康轻盐的高端款。', 10, 4);
INSERT INTO `goods` VALUES (214, '椰香腰果', '/picture/51-1.jpg', '/picture/51-2.jpg', '/picture/51-3.jpg', 48.9, '椰香腰果呈奶白色，表面裹满椰蓉，视觉上蓬松诱人，颗粒饱满。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上浓郁的椰香混合着腰果的坚果香，清新不腻。触感酥脆中带着椰蓉的绵软，入口先是椰蓉的香甜，随即腰果的醇香散开，味觉上甜而不腻（三星，满五星），椰香浓郁且持久，腰果的口感丰富有层次。主要原料：腰果、椰蓉、白砂糖、黄油，低温烘焙，保质期10个月，是坚果系列中甜口的特色款。', 10, 4);
INSERT INTO `goods` VALUES (215, '椒盐核桃', '/picture/52-1.jpg', '/picture/52-2.jpg', '/picture/52-3.jpg', 29.9, '椒盐核桃外壳呈深棕色，带有椒盐的均匀附着，视觉上纹理清晰，易剥开。撬开外壳时发出“啪”的轻响，听觉上解压，嗅觉上椒盐的咸香混合着核桃的坚果香，咸香入味。触感果仁酥脆有嚼劲，入口先是椒盐的咸香，随即核桃的醇香散开，味觉上咸淡适中（二星，满五星），椒盐味掩盖了核桃的苦涩，口感更易接受。主要原料：核桃、椒盐粉、食用盐，低温烘焙，保质期12个月，是坚果系列中平价且风味佳的经典款。', 10, 4);
INSERT INTO `goods` VALUES (216, '原味碳烤鱿鱼丝', '/picture/53-1.jpg', '/picture/53-2.jpg', '/picture/53-3.jpg', 45.9, '原味碳烤鱿鱼丝呈深棕色，纹理清晰，视觉上丝丝分明，无碎渣。撕扯时能听到轻微的“嘶啦”声，听觉上有嚼劲，嗅觉上浓郁的碳烤鱿鱼香，混合着淡淡的海鲜咸香，无腥味。触感柔韧有嚼劲，不粘牙，入口先是鱿鱼的鲜甜，随即碳烤的焦香在舌尖散开，味觉上咸淡适中（二星，满五星），无添加人工香精，仅靠鱿鱼本身的鲜味提味，越嚼越有海鲜的回甘。主要原料：新鲜鱿鱼、食用盐、白砂糖，碳烤工艺锁鲜，保质期9个月，独立真空包装，是海鲜零食中经典的手撕休闲款。', 10, 5);
INSERT INTO `goods` VALUES (217, '香辣鳗鱼丝', '/picture/54-1.jpg', '/picture/54-2.jpg', '/picture/54-3.jpg', 52.9, '香辣鳗鱼丝呈红棕色，表面裹满香辣调味料，视觉上油亮诱人，丝条均匀。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的鳗鱼鲜香混合着辣椒的辛香，香气扑鼻。触感柔韧有嚼劲，入口先是鳗鱼的鲜甜，随即香辣味在舌尖散开，味觉上辣度适中（四星，满五星），咸香入味，鳗鱼的鲜味与辣椒的辛香融合恰到好处。主要原料：鳗鱼、辣椒面、花椒粉、食用盐，低温烘烤，保质期8个月，是海鲜零食中重口味的特色款。', 10, 5);
INSERT INTO `goods` VALUES (218, '原味即食烤虾', '/picture/55-1.jpg', '/picture/55-2.jpg', '/picture/55-3.jpg', 68.9, '原味即食烤虾呈淡红色，视觉上虾身完整，个头均匀，肉质紧实。咬开时发出“咔嚓”的脆响（虾壳），听觉上满足，嗅觉上浓郁的鲜虾烘烤香，清新无腥味。触感虾壳酥脆，虾肉紧实有嚼劲，入口先是虾壳的咸香，随即虾肉的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留鲜虾的自然风味。主要原料：新鲜海虾、食用盐，低温碳烤，保质期10个月，独立包装，是海鲜零食中高蛋白的健康款。', 10, 5);
INSERT INTO `goods` VALUES (219, '烧烤味鱿鱼须', '/picture/56-1.jpg', '/picture/56-2.jpg', '/picture/56-3.jpg', 49.9, '烧烤味鱿鱼须呈深棕色，表面裹满烧烤调味料，视觉上须足完整，无断节。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的烧烤香料香混合着鱿鱼的鲜香，层次丰富。触感柔韧有嚼劲，不塞牙，入口先是鱿鱼的鲜甜，随即烧烤料的咸香与微辣在舌尖散开，味觉上咸甜辣平衡（三星，满五星），烧烤味浓郁且不掩盖鱿鱼的鲜味。主要原料：鱿鱼须、烧烤调味料、食用盐、白砂糖，碳烤工艺，保质期8个月，是海鲜零食中风味浓郁的热门款。', 10, 5);
INSERT INTO `goods` VALUES (220, '泡椒味鱼皮', '/picture/57-1.jpg', '/picture/57-2.jpg', '/picture/57-3.jpg', 38.9, '泡椒味鱼皮呈淡黄色，点缀着泡椒的红色，视觉上色泽鲜亮，鱼皮完整。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上泡椒的酸辣香混合着鱼皮的鲜香，独特诱人。触感酥脆不粘牙，入口先是泡椒的酸辣，随即鱼皮的鲜香散开，味觉上酸辣适中（四星，满五星），鱼皮的酥脆与泡椒的酸爽融合，越嚼越香。主要原料：鱼皮、泡椒、食用盐、白醋，低温油炸（控油），保质期9个月，是海鲜零食中酸辣风味的小众款。', 10, 5);
INSERT INTO `goods` VALUES (221, '原味银鱼仔', '/picture/58-1.jpg', '/picture/58-2.jpg', '/picture/58-3.jpg', 42.9, '原味银鱼仔呈银白色，视觉上体型小巧均匀，无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的银鱼鲜香，混合着淡淡的海盐香，清新自然。触感柔韧有嚼劲，入口先是银鱼的鲜甜，随即海盐的咸香提味，味觉上咸淡适中（一星，满五星），无添加人工香精，保留银鱼的自然风味。主要原料：银鱼、食用盐、白砂糖，低温烘烤，保质期10个月，独立小包装，是海鲜零食中便携的休闲款。', 10, 5);
INSERT INTO `goods` VALUES (222, '麻辣味花蛤肉', '/picture/59-1.jpg', '/picture/59-2.jpg', '/picture/59-3.jpg', 55.9, '麻辣味花蛤肉呈红棕色，表面裹满麻辣调味料，视觉上肉质饱满，无沙粒。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的麻辣香混合着花蛤的鲜香，香气扑鼻。触感肉质紧实有嚼劲，入口先是花蛤的鲜甜，随即麻辣味在舌尖散开，味觉上麻辣适中（五星，满五星），咸香入味，花蛤的鲜味与麻辣味融合恰到好处。主要原料：花蛤肉、辣椒面、花椒粉、食用盐，高温灭菌，保质期12个月，罐装密封，是海鲜零食中重口味的下酒菜。', 10, 5);
INSERT INTO `goods` VALUES (223, '芝士味鳕鱼粒', '/picture/60-1.jpg', '/picture/60-2.jpg', '/picture/60-3.jpg', 62.9, '芝士味鳕鱼粒呈奶白色，表面有芝士粉的均匀附着，视觉上颗粒饱满，质地细腻。咬下时发出轻微的“噗”声，听觉上柔和，嗅觉上浓郁的芝士香混合着鳕鱼的鲜香，醇厚诱人。触感绵软有嚼劲，入口先是芝士的咸香，随即鳕鱼的鲜甜散开，味觉上咸甜平衡（二星，满五星），芝士味浓郁且不腻，鳕鱼的口感绵密。主要原料：鳕鱼肉、芝士粉、鸡蛋、食用盐，低温烘烤，保质期8个月，是海鲜零食中适合儿童的营养款。', 10, 5);
INSERT INTO `goods` VALUES (224, '盐焗味蛏子干', '/picture/62-1.jpg', '/picture/62-2.jpg', '/picture/62-3.jpg', 72.9, '盐焗味蛏子干呈淡黄色，视觉上肉质饱满，无沙无杂质。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上淡淡的海盐香混合着蛏子的鲜香，清新自然。触感肉质紧实有嚼劲，入口先是海盐的咸香，随即蛏子的鲜甜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留蛏子的自然风味。主要原料：蛏子、食用海盐，低温盐焗，保质期12个月，是海鲜零食中高端的干货款。', 10, 5);
INSERT INTO `goods` VALUES (225, '蔓越莓软心饼干', '/picture/63-1.jpg', '/picture/63-2.jpg', '/picture/63-3.jpg', 18.9, '蔓越莓软心饼干外皮呈浅焦糖色，能看到暗红的蔓越莓果干嵌在其中，视觉上诱人十足。咬开时没有清脆声响，而是略带软糯的质感，嗅觉上蔓越莓的酸甜果香混合着黄油香气，清新不腻。触感外皮微酥，内芯软糯，入口先是黄油饼干的绵密，随即蔓越莓的酸甜在口腔中迸发，果干的嚼劲与饼干的软嫩融合，味觉上甜中带酸，层次丰富。主要原料：蔓越莓干、黄油、低筋面粉、糖粉，甜度：四星（满五星），保质期8个月，果干含量≥20%，是饼干系列中软心口感的代表，适合喜欢酸甜风味的人群。', 10, 1);
INSERT INTO `goods` VALUES (226, '阖家欢乐坚果礼盒', '/picture/64-1.jpg', '/picture/64-2.jpg', '/picture/64-3.jpg', 198.9, '阖家欢乐坚果礼盒外包装为中国红主色调，搭配金色祥云图案，视觉上喜庆大气，礼盒内包含巴旦木、夏威夷果、腰果、开心果、碧根果等8款坚果，独立罐装。开启礼盒时能听到礼盒盖的“啪”声，听觉上有仪式感，嗅觉上混合着各类坚果的醇香，浓郁不腻。触感礼盒质感厚实，坚果罐密封严实，每款坚果颗粒饱满酥脆，入口根据品类不同，或清甜或咸香，味觉上覆盖甜、咸、原味等多种风味，满足不同口味需求。所有坚果均采用低温烘焙工艺，无添加防腐剂，保质期12个月，是节日礼盒中经典的阖家分享款，适合春节、中秋等传统节日馈赠。', 10, 8);
INSERT INTO `goods` VALUES (227, '缤纷果干礼盒', '/picture/65-1.jpg', '/picture/65-2.jpg', '/picture/65-3.jpg', 168.9, '缤纷果干礼盒外包装为多彩渐变设计，视觉上活泼亮眼，礼盒内包含葡萄干、蔓越莓干、芒果干、草莓干、黄桃干等10款果干，独立小包装。开启时发出礼盒丝带的“嘶啦”声，听觉上有仪式感，嗅觉上混合着各类水果的香甜，清新自然。触感果干肉质饱满，软糯有嚼劲，入口根据品类不同，或酸甜或清甜，味觉上无添加人工香精，仅靠水果自然提味，甜度适中（二星至四星，满五星）。所有果干均采用冻干锁鲜工艺，保质期18个月，是节日礼盒中适合儿童与女性的清甜款。', 10, 8);
INSERT INTO `goods` VALUES (228, '年味肉食礼盒', '/picture/66-1.jpg', '/picture/66-2.jpg', '/picture/66-3.jpg', 258.9, '年味肉食礼盒外包装为复古国潮设计，视觉上年味十足，礼盒内包含酱牛肉、卤猪蹄、烤肠、熏鸡、香辣鸭脖等8款肉食，真空独立包装。开启时能听到真空包装的“啪”声，听觉上解压，嗅觉上混合着卤香、烤香等多种肉食香气，浓郁诱人。触感肉食肉质紧实，或酥烂或有嚼劲，入口根据品类不同，或咸香或麻辣，味觉上咸淡适中，风味浓郁且不腻。所有肉食均采用高温灭菌工艺，保质期9个月，是节日礼盒中适合家庭聚餐的硬菜款。', 10, 8);
INSERT INTO `goods` VALUES (229, '茶点饼干礼盒', '/picture/67-1.jpg', '/picture/67-2.jpg', '/picture/67-3.jpg', 158.9, '茶点饼干礼盒外包装为新中式设计，搭配水墨山水图案，视觉上雅致大气，礼盒内包含黄油曲奇、抹茶饼干、椰香薄脆、香葱苏打等10款饼干，独立小包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着黄油、奶香、茶香等多种香气，清新不腻。触感饼干或酥松或薄脆，入口根据品类不同，或香甜或咸香，味觉上甜度覆盖一星至四星（满五星），满足不同茶点需求。所有饼干均采用低温烘烤工艺，保质期10个月，是节日礼盒中适合品茶搭配的雅致款。', 10, 8);
INSERT INTO `goods` VALUES (230, '南瓜味米饼', '/picture/41-1.jpg', '/picture/41-2.jpg', '/picture/41-3.jpg', 19.9, '南瓜味米饼呈淡黄色，视觉上有南瓜泥的自然色泽，造型为卡通圆形，萌趣十足。掰开时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上南瓜的香甜混合着大米的清香，清新自然。触感酥脆易嚼，入口先是南瓜的清甜，随即大米的醇香散开，味觉上甜度极低（一星，满五星），无添加蔗糖。主要原料：大米粉、南瓜泥、食用盐、植物油，保质期12个月，非油炸膨化，是儿童零食中健康清淡的休闲款。', 10, 3);
INSERT INTO `goods` VALUES (231, '海鲜臻品礼盒', '/picture/69-1.jpg', '/picture/69-2.jpg', '/picture/69-3.jpg', 298.9, '海鲜臻品礼盒外包装为深海蓝主色调，视觉上高端大气，礼盒内包含烤虾、鱿鱼丝、鳗鱼丝、花蛤肉等8款海鲜零食，独立真空包装。开启时能听到真空包装的轻响，听觉上有质感，嗅觉上混合着海鲜的鲜香与烘烤香，清新无腥味。触感海鲜零食或柔韧或酥脆，入口根据品类不同，或鲜甜或麻辣，味觉上咸淡适中，保留海鲜的自然风味。所有海鲜均采用低温碳烤或高温灭菌工艺，保质期8-12个月不等，是节日礼盒中高端的海鲜特色款。', 10, 8);
INSERT INTO `goods` VALUES (232, '五谷杂粮礼盒', '/picture/70-1.jpg', '/picture/70-2.jpg', '/picture/70-3.jpg', 148.9, '五谷杂粮礼盒外包装为自然米色主色调，搭配谷物图案，视觉上健康质朴，礼盒内包含大米、小米、黑米、红豆、薏米等10款杂粮，独立密封罐装。开启时发出罐盖的“啪”声，听觉上解压，嗅觉上混合着各类谷物的清香，自然无异味。触感杂粮颗粒饱满，质地干燥，烹饪后口感或软糯或有嚼劲，入口根据品类不同，或清甜或清淡，味觉上无额外调味，保留谷物的自然风味。所有杂粮均无添加防腐剂，保质期18个月，是节日礼盒中适合馈赠长辈的健康款。', 10, 8);
INSERT INTO `goods` VALUES (233, '地方特产礼盒', '/picture/72-1.jpg', '/picture/72-2.jpg', '/picture/72-3.jpg', 228.9, '地方特产礼盒外包装为地域特色设计，印有当地地标图案，视觉上极具特色，礼盒内包含本地糕点、酱菜、坚果、肉食等10款地方特产，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各类特产的独特香气，浓郁诱人。触感特产或软糯或酥脆，入口根据品类不同，或咸香或香甜，味觉上贴合当地风味，咸淡适中，风味正宗。所有特产均采用传统工艺制作，保质期6-12个月不等，是节日礼盒中极具地域特色的馈赠款。', 10, 8);
INSERT INTO `goods` VALUES (234, '低糖健康礼盒', '/picture/73-1.jpg', '/picture/73-2.jpg', '/picture/73-3.jpg', 188.9, '低糖健康礼盒外包装为清新绿色主色调，视觉上健康自然，礼盒内包含无糖饼干、低糖坚果、无糖酸奶溶豆、杂粮脆片等10款低糖零食，独立包装。开启时发出礼盒盖的轻响，听觉上温和，嗅觉上混合着谷物香、奶香等清淡香气，无甜腻味。触感零食或酥松或酥脆，入口根据品类不同，或清淡或微甜，味觉上甜度均≤一星（满五星），无添加蔗糖。所有零食均采用健康工艺制作，保质期8-12个月不等，是节日礼盒中适合控糖人群的健康款。', 10, 8);
INSERT INTO `goods` VALUES (235, '环球零食礼盒', '/picture/74-1.jpg', '/picture/74-2.jpg', '/picture/74-3.jpg', 288.9, '环球零食礼盒外包装为多国风情设计，视觉上时尚大气，礼盒内包含进口饼干、巧克力、坚果、果干等12款全球特色零食，独立包装。开启时发出礼盒丝带的轻响，听觉上有仪式感，嗅觉上混合着各国零食的独特香气，层次丰富。触感零食或酥松或绵密，入口根据品类不同，或甜香或咸香，味觉上覆盖不同国家的风味特色，甜度与咸度适中。所有零食均为正规进口，保质期6-12个月不等，是节日礼盒中适合年轻群体的时尚款。', 10, 8);
INSERT INTO `goods` VALUES (236, '进口黑金松露巧克力', '/picture/75-1.jpg', '/picture/75-2.jpg', '/picture/75-3.jpg', 198.9, '进口黑金松露巧克力呈深棕色的球形，表面裹有可可粉，视觉上哑光高级，单颗独立金箔包装。掰开时能听到巧克力脆皮的轻微脆响，听觉上柔和，嗅觉上浓郁的黑松露香气混合着可可的醇香，层次丰富且不腻。触感应指即融，内芯绵密丝滑，入口先是可可的微苦，随即黑松露的独特香气在口腔中散开，味觉上甜苦平衡（三星，满五星），可可含量≥70%，无添加代可可脂，回味悠长且有松露的独特回甘。主要原料：进口可可液块、黑松露粉、淡奶油，冷链运输保鲜，保质期6个月，是高端零食中巧克力控的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (237, '特级冻干榴莲干', '/picture/76-1.jpg', '/picture/76-2.jpg', '/picture/76-3.jpg', 168.9, '特级冻干榴莲干采用泰国金枕榴莲制作，呈淡黄色，视觉上果肉纹理清晰，无碎渣。咬下时发出“咔嚓”的脆响，听觉上清脆利落，嗅觉上浓郁的榴莲果香，纯正且无香精味。触感酥脆易嚼，入口即化，先是榴莲的香甜在舌尖散开，随即淡淡的奶香回味，味觉上甜而不腻（四星，满五星），冻干工艺保留90%以上榴莲营养，无添加蔗糖。主要原料：泰国金枕榴莲果肉，冻干锁鲜工艺，保质期12个月，独立密封包装，是高端零食中榴莲爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (238, '顶级鱼子酱薯片', '/picture/77-1.jpg', '/picture/77-2.jpg', '/picture/77-3.jpg', 228.9, '顶级鱼子酱薯片呈薄透的淡黄色，表面均匀附着鱼子酱与芝士粉，视觉上质感十足，单片独立包装。咬下时发出“啪”的清脆声响，听觉上解压，嗅觉上浓郁的鱼子酱咸香混合着芝士的奶香，醇厚诱人。触感薄脆易嚼，入口即化，先是鱼子酱的咸鲜在舌尖散开，随即芝士的醇香回味，味觉上咸甜平衡（二星，满五星），薯片采用非转基因马铃薯制作，无添加人工色素。主要原料：马铃薯片、鱼子酱、芝士粉、黄油，低温烘烤工艺，保质期8个月，是高端零食中轻奢的休闲款。', 10, 11);
INSERT INTO `goods` VALUES (239, '精选松茸坚果混合装', '/picture/78-1.jpg', '/picture/78-2.jpg', '/picture/78-3.jpg', 258.9, '精选松茸坚果混合装包含松茸碎、夏威夷果、碧根果、开心果等高端坚果，视觉上颗粒饱满，配色自然。混合时能听到坚果碰撞的轻微声响，听觉上解压，嗅觉上松茸的独特清香混合着坚果的醇香，层次独特。触感坚果酥脆，松茸碎绵软，入口先是坚果的醇香，随即松茸的清鲜散开，味觉上咸淡适中（一星，满五星），无添加人工调味，保留食材自然风味。主要原料：精选松茸、进口坚果，低温烘焙工艺，保质期10个月，独立小包装，是高端零食中兼具营养与口感的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (240, '法式鹅肝酱饼干', '/picture/79-1.jpg', '/picture/79-2.jpg', '/picture/79-3.jpg', 188.9, '法式鹅肝酱饼干采用法式薄脆饼干搭配手工鹅肝酱，视觉上饼干金黄酥脆，鹅肝酱质地绵密。掰开饼干时发出“咔嚓”的脆响，听觉上清脆，嗅觉上鹅肝酱的浓郁醇香混合着饼干的黄油香，诱人食欲。触感饼干酥脆，鹅肝酱绵密，入口先是饼干的酥松，随即鹅肝酱的醇厚在口腔中散开，味觉上咸香适中（二星，满五星），无腥味，鹅肝酱含量≥40%。主要原料：法式薄脆饼干、新鲜鹅肝、黄油、食用盐，低温冷藏工艺，保质期6个月，是高端零食中法式风味的特色款。', 10, 11);
INSERT INTO `goods` VALUES (241, '冰岛即食海参', '/picture/80-1.jpg', '/picture/80-2.jpg', '/picture/80-3.jpg', 398.9, '冰岛即食海参呈深褐色，视觉上肉质厚实，参刺完整，独立真空包装。切开时能听到海参肉质的轻微“咯吱”声，听觉上有弹性，嗅觉上淡淡的海鲜咸香，无腥味。触感肉质Q弹有嚼劲，入口先是海参的鲜甜，随即淡淡的鲍汁提味（鲍汁款），味觉上咸淡适中（一星，满五星），无添加防腐剂，采用高温灭菌工艺锁鲜。主要原料：冰岛进口海参、鲍汁（可选），保质期12个月，开袋即食，是高端零食中滋补养生的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (242, '日式和牛脆片', '/picture/81-1.jpg', '/picture/81-2.jpg', '/picture/81-3.jpg', 268.9, '日式和牛脆片采用和牛雪花部位制作，呈浅棕色，视觉上纹理清晰，薄如蝉翼。咬下时发出“咔嚓”的脆响，听觉上满足，嗅觉上和牛的醇香混合着日式照烧的甜香，浓郁不腻。触感薄脆易嚼，入口先是和牛的鲜香，随即照烧的甜咸在舌尖散开，味觉上甜咸平衡（三星，满五星），无添加人工香精，保留和牛的自然风味。主要原料：日式和牛、照烧酱、食用盐，低温烘烤工艺，保质期9个月，独立密封包装，是高端零食中肉食爱好者的必选款。', 10, 11);
INSERT INTO `goods` VALUES (243, '顶级白松露坚果酱', '/picture/82-1.jpg', '/picture/82-2.jpg', '/picture/82-3.jpg', 298.9, '顶级白松露坚果酱呈浅棕色，质地绵密，视觉上无颗粒感，玻璃罐装配金色瓶盖。搅拌时触感顺滑，听觉上无明显声响，嗅觉上白松露的独特清香混合着坚果的醇香，层次丰富。入口绵密顺滑，先是坚果的香甜在舌尖散开，随即白松露的清鲜回味，味觉上甜咸平衡（二星，满五星），可搭配面包、饼干食用，风味独特。主要原料：白松露粉、榛子仁、杏仁、黄油，低温熬煮工艺，保质期12个月，是高端零食中轻奢的佐餐款。', 10, 11);
INSERT INTO `goods` VALUES (244, '澳洲进口芒果干', '/picture/83-1.jpg', '/picture/83-2.jpg', '/picture/83-3.jpg', 158.9, '澳洲进口芒果干采用澳洲凯特芒制作，呈金黄色，视觉上果肉厚实，纹理清晰，无添加色素。咬下时发出轻微的“咯吱”声，听觉上有嚼劲，嗅觉上浓郁的芒果果香，纯正且无香精味。触感肉质饱满，软糯有嚼劲，不粘牙，入口先是芒果的清甜，随即淡淡的果酸提味，味觉上甜酸平衡（三星，满五星），无添加蔗糖，仅靠芒果自然提甜。主要原料：澳洲凯特芒果肉，冻干锁鲜工艺，保质期18个月，独立密封包装，是高端零食中果干类的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (245, '奢享鱼子酱巧克力', '/picture/84-1.jpg', '/picture/84-2.jpg', '/picture/84-3.jpg', 288.9, '奢享鱼子酱巧克力呈球形，外层为黑巧克力，内芯包裹鱼子酱夹心，视觉上黑金配色，高级感十足。咬开时能听到巧克力脆皮的脆响，听觉上满足，嗅觉上黑巧克力的微苦混合着鱼子酱的咸鲜，层次独特。触感外层酥脆，内芯绵密，入口先是黑巧克力的醇厚，随即鱼子酱的咸鲜在口腔中散开，味觉上甜咸平衡（二星，满五星），可可含量≥80%，鱼子酱为进口顶级款。主要原料：进口黑巧克力、顶级鱼子酱、淡奶油，冷链保鲜，保质期6个月，是高端零食中极具特色的奢享款。', 10, 11);
INSERT INTO `goods` VALUES (246, '童趣零食礼盒', '/picture/68-1.jpg', '/picture/68-2.jpg', '/picture/68-3.jpg', 128.9, '童趣零食礼盒外包装为卡通萌趣设计，印有经典动画形象，视觉上吸引儿童，礼盒内包含动物饼干、星星软糖、鳕鱼肠、溶豆、磨牙棒等12款儿童零食，独立小包装。开启时发出礼盒丝带的轻响，听觉上活泼，嗅觉上混合着奶香、果香等清新香气，无刺鼻味。触感零食或酥松或软糯，专为儿童设计口感，入口根据品类不同，或清甜或咸香，味觉上甜度均≤三星（满五星），无添加人工色素与香精。所有零食均符合儿童食品标准，保质期6-18个月不等，是节日礼盒中适合馈赠有娃家庭的童趣款。', 10, 8);
